<template>
  <section class="p-0" style="border-top:10px solid #414e5e;">
    <div class="container-fluid p-0">
      <div class="row p-0 m-0">
        <div class="col-12 mt-0 p-0 border">
          <div class="resource_schedule_rw" id="divresource">
            <div id="calendar" :class="['daily', { monthly: activeView === 'Month', detailed: activeView === 'Day' }]" >
                <scheduler-header :resources="resources" :currentView="activeView" :from-date="fromDate" :to-date="toDate"
                :readonly="readonly" :offday="offday" @switchuser="switchuser" @navigate="handleNavigation" @save-completed="handleSaveCompleted" :key="activeView" />
                <div class="w-100 float-left position-relative" id="divuserdata">
                  <aside>
                    <resource-list v-for="(user, index) in resources" :key="user.userId" :user="user" :fromdate="fromDate"
                      :todate="toDate" :currentView="activeView" :shifthours="shiftHours" :readonly="readonly" :showTasks="showTasks"
                      @toggle-open="toggleOpen" @toggle-close="toggleClose"  @remove="removeUser"   :index="index" :keyy="activeView + renderKey"
                      @TentativeLeaveData="TentativeLeaveData" @CloneScheduleData="CloneScheduleData" @ProjectTaskDetailData="ProjectTaskDetailData"
                      @CellModelDetailData="CellModelDetailData"  @bookingAdded="handleBookingAdded" @AllUserTaskData="AllUserTaskData"
                      @bookingUpdated="handleBookingUpdated" @reloadKey="ReloadKey" @save-completed="handleSaveCompleted"
                      />
                  </aside>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </section>
</template>

<script>
import SchedulerHeader from './SchedulerHeader.vue'
import ResourceList from './ResourceList.vue'
import CellDetail from './CellDetail.vue'
import DataService from '../../../services/DataService'
export default {
  name: 'ResourceScheduler',
  props: {
    resources: {
      type: Array
    },
    shiftHours: {
      type: Number
    },
    offday: {
      type: String
    },
    activeView: {
      type: String
    },
    CellDeatils:{
      type:Object |Array
    },
    showTasks:{
      type:Boolean
    }
  },
  components: {
    SchedulerHeader,
    ResourceList,
    CellDetail
  },
  data() {
    return {
      fromDate: new Date,
      toDate: new Date,
      currentView: 'week',
      readonly: false,
      isLoading: false,
      IsCreate: false,
      renderKey: 0,
      showCellDetail: false,
      selectedCellData: null,
      allProjects: []
    }
  },
  created() {
    var d=this.CellDeatils
    this.initializeScheduler();
  },
  watch: {
    activeView: {
      handler(newView, oldView) {
        if (newView !== oldView && oldView) {
          this.updateDateRangeForView(newView);
        }
      },
      immediate: false
    },
    resources: {
      handler(newResources) {
        // Extend date range if bookings extend beyond current range
        if (newResources && newResources.length > 0) {
          this.$nextTick(() => {
            this.extendDateRangeForBookings();
          });
        }
      },
      deep: true,
      immediate: false
    }
  },
  methods: {
    ReloadKey()
    {
      debugger
       this.$emit('reloadKeys');
    },
    async initializeScheduler() {
      console.log('initializeScheduler ',this.activeView);
      if (!this.fromDate) {
        this.fromDate = new Date();
      }
      this.updateDateRangeForView(this.activeView || 'week');
    },
    updateDateRangeForView(view, baseDate = null) {
      // Use provided baseDate or default to today
      const base = baseDate ? new Date(baseDate) : new Date();
      base.setHours(0, 0, 0, 0);

      switch(view) {
        case 'Day':
          // Day view - show 1 month starting from Monday of base week, ending on Sunday
          const baseCopyDay = new Date(base);
          const dayOfWeekDay = baseCopyDay.getDay();
          const diffToMondayDay = dayOfWeekDay === 0 ? -6 : 1 - dayOfWeekDay; // Adjust for Monday start
          const mondayDay = new Date(baseCopyDay);
          mondayDay.setDate(baseCopyDay.getDate() + diffToMondayDay);
          mondayDay.setHours(0, 0, 0, 0);

          // Calculate end date: 1 month from Monday, then find the last Sunday
          const endDateDay = new Date(mondayDay);
          endDateDay.setMonth(endDateDay.getMonth() + 1); // Add 1 month
          // Find the last Sunday of that period
          const lastSundayDay = new Date(endDateDay);
          const lastDayOfWeekDay = lastSundayDay.getDay();
          const diffToSundayDay = lastDayOfWeekDay === 0 ? 0 : 7 - lastDayOfWeekDay; // Days to next Sunday
          lastSundayDay.setDate(endDateDay.getDate() + diffToSundayDay);
          lastSundayDay.setHours(0, 0, 0, 0);

          this.fromDate = new Date(mondayDay);
          this.toDate = new Date(lastSundayDay);
          console.log('day view ',this.fromDate, this.toDate);
          break;

        case 'week':
          // Week view - show 2 months starting from Monday of base week, ending on Sunday
          const baseCopy = new Date(base);
          const dayOfWeek = baseCopy.getDay();
          const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek; // Adjust for Monday start (0=Sunday, 1=Monday)
          const monday = new Date(baseCopy);
          monday.setDate(baseCopy.getDate() + diffToMonday);
          monday.setHours(0, 0, 0, 0);

          // Calculate end date: 2 months from Monday, then find the last Sunday
          const endDate = new Date(monday);
          endDate.setMonth(endDate.getMonth() + 2); // Add 2 months
          // Find the last Sunday of that period
          const lastSunday = new Date(endDate);
          const lastDayOfWeek = lastSunday.getDay();
          const diffToSunday = lastDayOfWeek === 0 ? 0 : 7 - lastDayOfWeek; // Days to next Sunday
          lastSunday.setDate(endDate.getDate() + diffToSunday);
          lastSunday.setHours(0, 0, 0, 0);

          this.fromDate = new Date(monday);
          this.toDate = new Date(lastSunday);
        console.log('week view ',this.fromDate, this.toDate);
          break;

        case 'Month':
          // Month view - show 3 months
          this.fromDate = new Date(base.getFullYear(), base.getMonth(), 1);
          this.toDate = new Date(base.getFullYear(), base.getMonth() + 3, 0); // 3 months ahead
          console.log('month view ',this.fromDate, this.toDate);
          break;

        default:
          // Default to week view with 2 months range
          const baseCopy2 = new Date(base);
          const dayOfWeek2 = baseCopy2.getDay();
          const diffToMonday2 = dayOfWeek2 === 0 ? -6 : 1 - dayOfWeek2;
          const monday2 = new Date(baseCopy2);
          monday2.setDate(baseCopy2.getDate() + diffToMonday2);
          monday2.setHours(0, 0, 0, 0);

          const endDate2 = new Date(monday2);
          endDate2.setMonth(endDate2.getMonth() + 2);
          const lastSunday2 = new Date(endDate2);
          const lastDayOfWeek2 = lastSunday2.getDay();
          const diffToSunday2 = lastDayOfWeek2 === 0 ? 0 : 7 - lastDayOfWeek2;
          lastSunday2.setDate(endDate2.getDate() + diffToSunday2);
          lastSunday2.setHours(0, 0, 0, 0);

          this.fromDate = new Date(monday2);
          this.toDate = new Date(lastSunday2);
        console.log('default view ',this.fromDate, this.toDate);
      }
    },
    handleNavigation(navigationData) {
      const { direction, view } = navigationData;
      const currentView = view || this.activeView;

      let newBaseDate;

      if (direction === 'today') {
         // Navigate to today
         newBaseDate = new Date();
      }
      else if (direction === 'next') {
         // Start from current range end
         newBaseDate = new Date(this.toDate);
      }
      else {
         // 'prev' - start from current range start
         newBaseDate = new Date(this.fromDate);
      }

      // Normalize
      newBaseDate.setHours(0,0,0,0);

      // Shift by full view span
      switch(currentView) {
        case 'Day':
          if (direction === 'next') newBaseDate.setMonth(newBaseDate.getMonth() + 1);
          else if (direction === 'prev') newBaseDate.setMonth(newBaseDate.getMonth() - 1);
          break;
        case 'week':
          if (direction === 'next') newBaseDate.setMonth(newBaseDate.getMonth() + 2);
          else if (direction === 'prev') newBaseDate.setMonth(newBaseDate.getMonth() - 2);
          break;
        case 'Month':
          if (direction === 'next') newBaseDate.setMonth(newBaseDate.getMonth() + 3);
          else if (direction === 'prev') newBaseDate.setMonth(newBaseDate.getMonth() - 3);
          break;
        default:
          if (direction === 'next') newBaseDate.setMonth(newBaseDate.getMonth() + 2);
          else if (direction === 'prev') newBaseDate.setMonth(newBaseDate.getMonth() - 2);
      }

      // Update date range with new base date
      this.updateDateRangeForView(currentView, newBaseDate);

      // Extend date range if bookings require it
      this.$nextTick(() => {
        this.extendDateRangeForBookings();
      });
    },
    changeView(view) {
      this.currentView = view
    },
    async onSelectResource(resourceId) {
      const resource = this.resources.find(r => r.id === resourceId)
      if (resource) {
        const result = await getUserProjectTasks(resource.id, this.fromDate, this.toDate)
        resource.tasks = result
      }
    },
    async onUpdateBooking(updatedBooking) {
      const idx = this.resources.findIndex(r => r.id === updatedBooking.resourceId)
      if (idx !== -1) {
        const bookingIdx = this.resources[idx].bookings.findIndex(
          b => b.id === updatedBooking.id
        )
        if (bookingIdx !== -1) {
          this.$set(this.resources[idx].bookings, bookingIdx, updatedBooking)
        }
      }
    },

    toggleOpen(index) {
      this.resources.forEach((resource, i) => {
        this.$set(this.resources[i], 'isOpen', i === index);
      });
    },

    toggleClose(index) {
      this.$set(this.resources[index], 'isOpen', false);
    },
    removeUser(index) {
  // Remove the selected user
  this.resources.splice(index, 1);

  // Reassign indexes to each remaining user
  this.resources.forEach((res, i) => {
    this.$set(res, 'index', i);
  });

  // Force Vue to refresh the list if needed
  this.resources = [...this.resources];
},
    switchuser() {
      var vm = this;
      vm.$emit('IsFilterTrue');
    },
    TentativeLeaveData(UserId,data){
      this.$emit('NewTentativeLeaveData',UserId,data);
    },
    CloneScheduleData(data)
    {
      this.$emit('NewCloneScheduleData',data);
    },
    ProjectTaskDetailData(data)
    {

      this.$emit('NewProjectTaskDetailData',data);
    },
    CellModelDetailData(cellData) {
      this.$emit('bookingAdded',cellData)
    },
    closeCellDetail() {
      this.showCellDetail = false;
      this.selectedCellData = null;
    },
    handleBookingAdded(bookingData) {
      console.log('Booking saved:', bookingData);
      this.$emit('bookingAdded', bookingData);
    },
    onBookingPreviewAdded(event) {
      console.log("Booking preview received:", event);
      debugger;
      const user = this.resources.find(u => u.userId === event.resourceId);
      if (user) {
        if (!user.tempBookings) {
          this.$set(user, 'tempBookings', []);
        }
        const startDate = new Date(event.startDate);
        const endDate = new Date(event.endDate);
        const currentDate = new Date(startDate);
        while (currentDate <= endDate) {
          user.tempBookings = user.tempBookings.filter(
            b => new Date(b.date).toDateString() !== currentDate.toDateString()
          );

          user.tempBookings.push({
            date: new Date(currentDate),
            projectId: event.projectId,
            projectName: event.projectName,
            taskId: event.taskId,
            taskName: event.taskName,
            hours: event.hours,
            description: event.description,
            bookingType: event.bookingType
          });

          // Move to next day
          currentDate.setDate(currentDate.getDate() + 1);
        }
      }
      this.$forceUpdate();
    },
    AllUserTaskData(userId,StartDate,EndDate){
      const params = `userId=${userId}&startDate=${StartDate}&endDate=${EndDate}&isShow=ALL`;
      DataService.GetUserProjectTaskData(params).then((response) => {
        if(response.data.result.length>0){
          const user = this.resources.find(u => u.userId === userId);
          if (user) {
            this.$set(user, 'userTaskData', response.data.result);
          }
        }
      })
    },
    handleBookingUpdated(bookingData) {
      // Forward booking update event to parent
      this.$emit('bookingUpdated', bookingData);
      // Extend date range if needed after booking update
      this.extendDateRangeForBookings();
    },
    handleSaveCompleted(success) {
      debugger
      // Forward save-completed event to parent with the SAME event name
      this.$emit('save-completed', success);
    },
    extendDateRangeForBookings() {
      if (!this.resources || this.resources.length === 0) return;

      let minDate = null;
      let maxDate = null;

      // Find earliest start date and latest end date from all bookings
      this.resources.forEach(resource => {
        if (resource.bookings && Array.isArray(resource.bookings)) {
          resource.bookings.forEach(booking => {
            if (booking.is_change !== undefined && Number(booking.is_change) === 3) return;

            const startDate = this.parseBookingDate(booking.booking_start_date);
            const endDate = this.parseBookingDate(booking.booking_end_date);

            if (startDate && !isNaN(startDate.getTime())) {
              if (!minDate || startDate < minDate) {
                minDate = new Date(startDate);
                minDate.setHours(0, 0, 0, 0);
              }
            }

            if (endDate && !isNaN(endDate.getTime())) {
              if (!maxDate || endDate > maxDate) {
                maxDate = new Date(endDate);
                maxDate.setHours(0, 0, 0, 0);
              }
            }
          });
        }
      });

      // Extend date range if bookings extend beyond current range
      if (minDate && maxDate) {
        const currentFrom = new Date(this.fromDate);
        const currentTo = new Date(this.toDate);
        currentFrom.setHours(0, 0, 0, 0);
        currentTo.setHours(0, 0, 0, 0);

        let needsUpdate = false;

        // Adjust start date if booking starts earlier
        if (minDate < currentFrom) {
          // For week/Day views, adjust to Monday of that week
          if (this.activeView === 'week' || this.activeView === 'Day') {
            const dayOfWeek = minDate.getDay();
            const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
            const adjustedMonday = new Date(minDate);
            adjustedMonday.setDate(minDate.getDate() + diffToMonday);
            adjustedMonday.setHours(0, 0, 0, 0);
            this.fromDate = adjustedMonday;
          } else {
            this.fromDate = minDate;
          }
          needsUpdate = true;
        }

        // Adjust end date if booking ends later
        if (maxDate > currentTo) {
          // For week/Day views, adjust to Sunday of that week
          if (this.activeView === 'week' || this.activeView === 'Day') {
            const dayOfWeek = maxDate.getDay();
            const diffToSunday = dayOfWeek === 0 ? 0 : 7 - dayOfWeek;
            const adjustedSunday = new Date(maxDate);
            adjustedSunday.setDate(maxDate.getDate() + diffToSunday);
            adjustedSunday.setHours(0, 0, 0, 0);
            this.toDate = adjustedSunday;
          } else {
            this.toDate = maxDate;
          }
          needsUpdate = true;
        }

        if (needsUpdate) {
          console.log('Extended date range:', this.fromDate, this.toDate);
        }
      }
    },
    parseBookingDate(val) {
      if (!val && val !== 0) return null;
      if (val instanceof Date) return new Date(val);
      if (!isNaN(val) && String(val).length >= 10) {
        const s = String(val).length;
        if (s >= 13) return new Date(Number(val));
        return new Date(Number(val) * 1000);
      }
      if (typeof val === "string") {
        if (val.includes("T")) return new Date(val);
        if (!isNaN(val)) {
          const s = val.length;
          if (s >= 13) return new Date(Number(val));
          return new Date(Number(val) * 1000);
        }
        const got = new Date(val);
        if (!isNaN(got.getTime())) return got;
      }
      return new Date(val);
    }

  },
}
</script>

