<template>

    <section class="main-content">


        <link href="https://talygenv.github.io/Vue-UI-Content/Content/ResourceScheduling/style.css" rel="stylesheet" />
        <link href="https://talygenv.github.io/Vue-UI-Content/Content/ResourceScheduling/style-new.css"
            rel="stylesheet" />

        <div class="container-fluid p-0">
            <div class="row">
                <div class="col-md-12">
                    <div class="theme-primary partition-full">
                        <span class="p-name text-white">{{ $t('ResourceScheduling') }}</span>
                        <span class="p-actions float-right">
                            <a href="javascript:;"
                                :class="['p-action-btn', 'text-white', { active: activeView === 'Day' }]"
                                id="ancdayclick" title="Day" @click="activeview('Day')"><em class="fa fa-calendar"
                                    aria-hidden="true"></em><br>{{ $t('Day') }}</a>
                            <a href="javascript:;"
                                :class="['p-action-btn', 'text-white', { active: activeView === 'week' }]"
                                id="ancweekclick" title="week" @click="activeview('week')"><em class="fa fa-calendar"
                                    aria-hidden="true"></em><br>{{ $t('week') }}</a>
                            <a href="javascript:;"
                                :class="['p-action-btn', 'text-white', { active: activeView === 'Month' }]"
                                id="ancmonthclick" title="Month" @click="activeview('Month')"><em class="fa fa-calendar"
                                    aria-hidden="true"></em><br>{{ $t('Month') }}</a>
                            <a href="javascript:;" class="p-action-btn text-white" id="ancuserGuide"
                                @click="UserGuideModel" title="UserGuide"><span class="rs-userguide"></span><br>{{
                                $t('UserGuide') }}</a>
                            <a href="javascript:;" class="p-action-btn text-white" title="Collapse Widgets"
                                @click="Collapsetab" id="anccollapsewidget"><em
                                    :class="IsColapseTabs ? 'fa fa-angle-double-up' : 'fa fa-angle-double-down'"
                                    aria-hidden="true"></em>
                                <br>{{
                                    $t('Collapse') }} {{ $t('Widgets') }}</a>
                        </span>
                    </div>
                </div>
            </div>
            <div class="row res-widget">
                <div :class="['col-12 mt-2', { 'collapsed': !IsColapseTabs }]" id="divWidgetData">
                    <ul class="dashbord-widget" v-if="WidgetData.length > 0">
                        <li class="one_wid">
                            <h3>{{ WidgetData[0].name }}<br><span>{{ $t('Total') }} {{ $t('Shifts') }}</span></h3>
                            <em class="fa fa-sun-o" aria-hidden="true"></em>
                        </li>
                        <li class="two_wid cursor-pointer">
                            <h3>{{ WidgetData[0].value }}<br><span>{{ $t('Total') }} {{ $t('Employees') }}</span></h3>
                            <em class="fa fa-users" aria-hidden="true"></em>
                        </li>
                        <li class="three_wid">
                            <h3>{{ WidgetData[0].firstValue }}<br><span>{{ $t('TotalHours') }}</span></h3>
                            <em class="fa fa-braille" aria-hidden="true"></em>
                        </li>
                        <li class="two_wid cursor-pointer">
                            <h3>{{ WidgetData[0].secondValue == null ? 0.00 : WidgetData[0].secondValue }}<br><span>{{
                                $t('AllocatedHours') }}</span></h3>
                            <em class="fa fa-braille" aria-hidden="true"></em>
                        </li>
                        <li class="two_wid cursor-pointer">
                            <h3>
                                <!-- {{ WidgetData[0].firstValue - WidgetData[0].secondValue }} -->
                                {{
                                    WidgetData[0].firstValue - WidgetData[0].secondValue > 0 ?

                                        isNaN(WidgetData[0].firstValue - WidgetData[0].secondValue)
                                            ? '0.00'
                                            : (WidgetData[0].firstValue - WidgetData[0].secondValue).toFixed(2) : 0
                                }}
                                <br><span>{{ $t('FreeHours')
                                    }}</span>
                            </h3>
                            <em class="fa fa-coffee" aria-hidden="true"></em>
                        </li>
                    </ul>
                </div>
                <div class="col-12 mb-2 fontfix12">
                    <div class="mr-2 d-inline-block">
                        <span class="legend-Progress colorboxsquare"></span>{{ $t('FreeHours') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legend-pending colorboxsquare" style="background:#24a5ff;"></span>{{
                            $t('AllocatedHours') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legend-grey  colorboxsquare"></span>{{ $t('NotFree') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legend-ovrdue colorboxsquare"></span>{{ $t('OverLoad') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legend-light-grey colorboxsquare"></span>{{ $t('RSWeekEnd') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legends-red-damask colorboxsquare"></span>{{ $t('RSUserBusy') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legends-Apple colorboxsquare"></span>{{ $t('RSCompanyHoliday') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="d-inline-block"><em class="fa fa-ship mr-1 text-success"></em></span>{{
                            $t('leaveapproved') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="d-inline-block"><em class="fa fa-ship text-primary mr-1"></em></span>{{
                            $t('leavepending') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="d-inline-block"><em class="fa fa-user-times mr-1 text-muted"></em></span>{{
                            $t('TentativeLeave') }}
                    </div>
                    <!-- <div class="mr-2 d-inline-block float-right left_pane">
                        <span class="vert_txt">{{ $t('TaskviewinRightPanel') }}</span>
                        <div class="form-group">
                            <label class="switch float-right">
                                <input type="checkbox" id="chktaskview" name="chktaskview"
                                    class="dynamic custom-switch">
                                <span class="slider round">
                                    <span class="slider-yes">{{ $t('Yes') }}</span>
                                    <span class="slider-no">{{ $t('No') }}</span>
                                </span>
                            </label>
                        </div>
                    </div> -->
                    <div class="mr-2 d-inline-block float-right left_pane">
                        <span class="vert_txt">{{ $t('TaskviewinLeftPanel') }}</span>
                        <div class="form-group">
                            <label class="switch float-right">
                                <input type="checkbox" id="chktaskview" name="chktaskview" class="dynamic custom-switch"
                                    @click="toggleTasks">
                                <span class="slider round">
                                    <span class="slider-yes">{{ $t('Yes') }}</span>
                                    <span class="slider-no">{{ $t('No') }}</span>
                                </span>
                            </label>
                        </div>
                    </div>
                </div>
            </div>
            <div class="row" v-if="resources.length > 0">
                <div class="col-12 mt-2">
                    <ResourceScheduler :key="activeView + reloadKey" :resources="resources" :shiftHours="shiftHours"
                        :offday="offday" :activeView="activeView" :showTasks="showTasks" :CellDeatils="CellDeatils"
                        @IsFilterTrue="IsFilterTrue" @NewTentativeLeaveData="NewTentativeLeaveData"
                        @NewCloneScheduleData="NewCloneScheduleData"
                        @NewProjectTaskDetailData="NewProjectTaskDetailData" @bookingAdded="handleBookingAdded"
                        @bookingUpdated="handleBookingUpdated" @save-completed="handleSaveCompleted"
                        @reloadKeys="ReloadKey" />
                </div>
            </div>
        </div>

        <ResourcFilter v-if="IsResourcFilter" @AllSearchResource="AllSearchResource"
            @CloseResourceFilter="CloseResourceFilter"></ResourcFilter>
        <UserGuid v-if="ISuserGuideModel"></UserGuid>
        <AddTentativeLeave v-if="isAddTentativeLeave" :TentativeLeaveData="TentativeLeaveData"
            @CloseTentativeLeave="handleTentativeLeaveAdded" @ApplyTentaiveLeave="ApplyTentaiveLeave" />
        <CloneSchedule v-if="IsClone" :CloneScheduleData="CloneScheduleData" />
        <CellDetailBackup v-if="IsCellDeatil" :CellData="CellData" @saveBooking="saveBookingData"
            @Delete="DeleteBooking" />
        <ProjectTaskDetail v-if="IsTaskDetail" :TaskData="TaskData" @CloseProjectDetail="handleCloseProjectDetail" />
    </section>

</template>

<script>
import ResourceScheduler from './ResourceScheduler.vue'
import UserGuid from './UserGuid.vue';
import CloneSchedule from './CloneSchedule.vue';
import DataService from '../../../services/DataService';
import ResourcFilter from './ResourcFilter.vue'
import AddTentativeLeave from './AddTentativeLeave.vue'
import CellDetailBackup from './CellDetail - backup.vue';
import ProjectTaskDetail from './ProjectTaskDetail.vue'
import SchedulerHeader from './SchedulerHeader.vue';
export default {
    name: 'Create',
    components: { ResourceScheduler, ResourcFilter, UserGuid, AddTentativeLeave, CloneSchedule, CellDetailBackup, ProjectTaskDetail, SchedulerHeader },
    props: {
        setIsfilter: {
            type: Boolean
        }
    },
    data() {
        return {
            WidgetData: [],
            resources: [],
            shiftHours: 0,
            offday: 0,
            IsResourcFilter: true,
            activeView: 'week',
            IsColapseTabs: true,
            IsClone: false,
            ISuserGuideModel: false,
            isAddTentativeLeave: false,
            IsTaskDetail: false,
            IsCellDeatil: false,
            TentativeLeaveData: null,
            reloadKey: 0,
            CloneScheduleData: null,
            CellData: null,
            showTasks: false,
            CellDeatils: [],
            TaskData: '',
            lastUserId: null,
            lastShiftId: null,
        }
    },
    created() {
        this.GetResourcesBookingWidgetData();
        this.loadResources();
    },
    methods: {
        UserGuideModel() {
            this.ISuserGuideModel = true;
        },
        IsFilterTrue() {
            this.IsResourcFilter = true;
        },
        Collapsetab() {
            this.IsColapseTabs = !this.IsColapseTabs;
        },
        CloseResourceFilter() {
            this.IsResourcFilter = false;
        },
        AllSearchResource(data) {
            if (data.selectedUsers.length > 0) {
                var userId = data.selectedUsers.join(",");
                var shiftId = data.IsChooseShift;
                this.lastUserId = userId;
                this.lastShiftId = shiftId;
                this.loadResources(userId, shiftId);
            } else {
                this.lastUserId = null;
                this.lastShiftId = null;
                this.loadResources(null, null);
            }
            this.isLoading = false;
        },

        GetResourcesBookingWidgetData() {
            debugger
            var url = `startDate=&endDate=&projectId=&taskId=&userId=`;
            DataService.GetResourcesBookingWidgetData(url).then(res => {
                if (res.data.length > 0) {
                    this.WidgetData = res.data;
                }
            })
        },
        formatDate(date) {
            const d = new Date(date);
            const year = d.getFullYear();
            const month = String(d.getMonth() + 1).padStart(2, '0');
            const day = String(d.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}T00:00:00`;
        },

        saveBookingData(data) {
            debugger;
            this.IsCellDeatil = false;
            debugger
            const resource = this.resources.find(element => element.userId == data.resourceId);
            if (resource) {
                const bookingIndex = resource.bookings.findIndex(b => b.booking_id == data.booking_id);
                if (bookingIndex !== -1) {
                    const updatedBooking = {
                        ...resource.bookings[bookingIndex],
                        booking_start_date: this.formatDate(data.startDate),
                        booking_end_date: this.formatDate(data.endDate),
                        description: data.description,
                        is_change: data.is_change,
                        task_type: data.task_type,
                        project_id: data.projectId,
                        project_name: data.projectName,
                        resource_id: data.resourceId,
                        task_Id: data.taskId,
                        task_name: data.taskName,
                        working_on_off_days: data.working_day,
                        specific_stop_time: data.endTime,
                        specific_start_time: data.startTime,
                        per_day_working_hours: data.hours
                    };
                    this.$set(resource.bookings, bookingIndex, updatedBooking);
                    this.handleSaveCompleted(true);
                    this.$root.$emit('call-UpdateRecrds', { action: 'update', booking: resource.bookings[bookingIndex] });
                    // this.$root.$emit('call-UpdateRecrds',resource.bookings[bookingIndex]);
                }
            }
            else {
                const obj = {
                    booking_start_date: this.formatDate(data.startDate),
                    booking_end_date: this.formatDate(data.endDate),
                    booking_id: data.booking_id,
                    description: data.description,
                    is_change: data.is_change,
                    task_type: data.task_type,
                    project_id: data.projectId,
                    project_name: data.projectName,
                    resource_id: data.resourceId == null ? data.userId : data.resourceId,
                    task_Id: data.taskId,
                    task_name: data.taskName,
                    working_on_off_days: data.working_day,
                    specific_stop_time: data.endTime,
                    specific_start_time: data.startTime,
                    per_day_working_hours: data.hours
                };
                const Addresources = this.resources.find(element => element.userId == data.userId);                
                this.$root.$emit('call-UpdateRecrds', { action: 'create', booking: obj });
                Addresources.bookings.push(obj);
                this.resources.bookings.push(obj);
                this.handleSaveCompleted(true);

            }
            this.reloadKey++;
        },
        activeview(view) {
            this.activeView = view;
        },
        DeleteBooking(data) {

            let resourceIndex = -1;
            let bookingIndex = -1;
            this.resources.forEach((resource, rIdx) => {
                const bIdx = resource.bookings.findIndex(
                    booking => booking.booking_id === data.bookingId
                );
                if (bIdx !== -1) {
                    resourceIndex = rIdx;
                    bookingIndex = bIdx;
                }
            });

            if (resourceIndex !== -1 && bookingIndex !== -1) {
                this.resources[resourceIndex].bookings.splice(bookingIndex, 1);
                this.IsCellDeatil = false;
                this.ShowAlert(this.$t('DeletedSuccess', [this.$t('Task')]), "success", true, this.$t("Alert"));
            }
        },


        loadResources(userId, shiftId) {
            debugger
            this.isLoading = true
            try {
                this.resources = [];
                this.offday = 0;
                this.shiftHours = 0;
                const start = this.fromDate
                const end = this.toDate
                // Use provided parameters or stored ones, or empty string for all
                const finalUserId = userId !== undefined ? userId : (this.lastUserId !== null ? this.lastUserId : '');
                const finalShiftId = shiftId !== undefined ? shiftId : (this.lastShiftId !== null ? this.lastShiftId : '');
                var url = `userIds=${finalUserId}&startDate=&endDate=&shiftId=${finalShiftId}`;
                DataService.GetResourceBookingData(url).then((response) => {
                    debugger
                    if (response.data.resourceScheduling.listUserResult.length > 0) {
                        this.resources = response.data.resourceScheduling.listUserResult;
                        this.resources.forEach((element, index) => {
                            this.$set(element, 'isOpen', false);
                            this.$set(element, 'index', index);
                        });
                        this.shiftHours = response.data.resourceScheduling.shiftHours;
                        this.offday = response.data.resourceScheduling.offday;
                        this.CloseResourceFilter();
                    } else {
                        this.resources = [];
                        this.shiftHours = 0;
                        this.offday = 0;
                        this.isLoading = false;
                    }
                })

            } finally {
                this.isLoading = false
            }
        },
        NewTentativeLeaveData(dta) {
            var ths = this;
            ths.TentativeLeaveData = dta;
            ths.isAddTentativeLeave = true;
        },
        NewCloneScheduleData(dta) {
            var ths = this;
            ths.CloneScheduleData = dta;
            ths.IsClone = true;
        },
        NewProjectTaskDetailData(data) {
            this.TaskData = data != '' ? data : '';
            this.IsTaskDetail = true;
        },
        handleCloseProjectDetail(data) {
            const userIndex = this.resources.findIndex(user => user.userId === data.resource_id);
            if (userIndex !== -1) {
                this.$set(this.resources[userIndex], 'isOpen', false);
                this.reloadKey++;
            }
            this.IsTaskDetail = false;

        },
        handleTentativeLeaveAdded() {
            var ths = this;
            ths.isAddTentativeLeave = false;
        },
        ApplyTentaiveLeave(UserId, data) {
            debugger
            const userIndex = this.resources.findIndex(user => user.userId === UserId);
            if (userIndex !== -1) {
                this.$set(this.resources[userIndex], 'userTentativeLeave', data);
                this.$set(this.resources[userIndex], 'isOpen', false);
                this.reloadKey++;
            }
        },
        ReloadKey() {
            this.reloadKey++;
        },
        handleBookingAdded(bookingData) {
            this.IsCellDeatil = true;
            this.CellData = bookingData;
        },
        toggleTasks() {

            this.showTasks = !this.showTasks
        },
        handleBookingUpdated(bookingData) {
            console.log('Booking updated:', bookingData);
        },
        handleSaveCompleted(success) {
           // debugger
            // Reload resources after save is completed
            if (success) {
                // Reload resources with the same filter parameters that were used before
                this.loadResources(this.lastUserId, this.lastShiftId);
                // Also reload widget data
                this.GetResourcesBookingWidgetData();
                // Force component re-render
                this.reloadKey++;
            }
        }
    }
}
</script>
<style scoped>
#divWidgetData {
    transition: all 0.3s ease;
    overflow: hidden;
}

.collapsed {
    height: 0;
    padding: 0;
    margin: 0;
    opacity: 0;
}

.col-12 {
    padding: 10px;
}

.p-action-btn {
    cursor: pointer;
}
</style>
