<template>
  <div v-if="showPopup" class="booking-popup-overlay">
    <div class="booking-popup">
      <div class="popup-header">
        <h3>{{ isEditMode ? $t('EditBooking') : $t('AddBooking') }}</h3>
        <button @click="closePopup" class="close-btn">&times;</button>
      </div>

      <div class="popup-content">
        <!-- Project Dropdown -->
        <div class="form-group">
          <label>{{ $t('Project') }}: <span class="required">*</span></label>
          <select v-model="bookingData.projectId" @change="onProjectChange" class="form-control" :disabled="isLoading">
            <option value="">{{ $t('SelectProject') }}</option>
            <option v-for="project in projects" :key="project.projectId" :value="project.projectId">
              {{ project.projectName }}
            </option>
          </select>
          <span v-if="errors.projectId" class="error">{{ errors.projectId }}</span>
        </div>

        <!-- Task Dropdown -->
        <div class="form-group">
          <label>{{ $t('Task') }}: <span class="required">*</span></label>
          <select v-model="bookingData.taskId" class="form-control" :disabled="isLoading">
            <option value="">{{ $t('SelectTask') }}</option>
            <option v-for="task in tasks" :key="task.taskId" :value="task.taskId">
              {{ task.taskName }}
            </option>
          </select>
          <span v-if="errors.taskId" class="error">{{ errors.taskId }}</span>
        </div>

        <!-- Date Range -->
        <div class="row">
          <div class="col-6">
            <div class="form-group">
              <label>{{ $t('From') }}: <span class="required">*</span></label>
              <input type="date" v-model="bookingData.bookingStartDate" class="form-control" :disabled="isLoading">
              <span v-if="errors.bookingStartDate" class="error">{{ errors.bookingStartDate }}</span>
            </div>
          </div>
          <div class="col-6">
            <div class="form-group">
              <label>{{ $t('To') }}: <span class="required">*</span></label>
              <input type="date" v-model="bookingData.bookingEndDate" class="form-control" :disabled="isLoading">
              <span v-if="errors.bookingEndDate" class="error">{{ errors.bookingEndDate }}</span>
            </div>
          </div>
        </div>

        <!-- Booking Type -->
        <div class="form-group">
          <label>{{ $t('Type') }}:</label>
          <div class="radio-group">
            <label>
              <input type="radio" v-model="bookingType" value="PD" :disabled="isLoading"> {{ $t('BookHoursPerDay') }}
            </label>
            <label>
              <input type="radio" v-model="bookingType" value="ST" :disabled="isLoading"> {{ $t('BookSpecificTime') }}
            </label>
          </div>
        </div>

        <!-- Hours Per Day -->
        <div v-if="bookingType === 'PD'" class="row">
          <div class="col-6">
            <div class="form-group">
              <label>{{ $t('HoursPerDay') }}: <span class="required">*</span></label>
              <input type="number" v-model="bookingData.hours" min="0" max="24" class="form-control" :disabled="isLoading">
            </div>
          </div>
          <div class="col-6">
            <div class="form-group">
              <label>{{ $t('Minutes') }}: <span class="required">*</span></label>
              <input type="number" v-model="bookingData.minutes" min="0" max="59" class="form-control" :disabled="isLoading">
            </div>
          </div>
        </div>

        <!-- Specific Time -->
        <div v-if="bookingType === 'ST'" class="row">
          <div class="col-6">
            <div class="form-group">
              <label>{{ $t('TimePerDay') }}: <span class="required">*</span></label>
              <input type="time" v-model="bookingData.specificStartTime" class="form-control" :disabled="isLoading">
            </div>
          </div>
          <div class="col-6">
            <div class="form-group">
              <label>{{ $t('To') }}: <span class="required">*</span></label>
              <input type="time" v-model="bookingData.specificStopTime" class="form-control" :disabled="isLoading">
            </div>
          </div>
        </div>

        <!-- Description -->
        <div class="form-group">
          <label>{{ $t('Description') }}:</label>
          <textarea v-model="bookingData.description" class="form-control" rows="3" :disabled="isLoading"></textarea>
        </div>
      </div>

      <div class="popup-footer">
        <button @click="saveBooking" class="btn btn-primary" :disabled="isLoading">
          {{ isLoading ? $t('Saving') + '...' : $t('Save') }}
        </button>
        <button @click="closePopup" class="btn btn-secondary" :disabled="isLoading">{{ $t('Cancel') }}</button>
        <button v-if="isEditMode" @click="deleteBooking" class="btn btn-danger" :disabled="isLoading">{{ $t('Delete') }}</button>
      </div>
    </div>
  </div>
</template>

<script>
import DataService from '../../../services/DataService.js';

export default {
  name: 'BookingPopup',
  props: {
    showPopup: Boolean,
    cellData: Object,
    isEditMode: Boolean,
    existingBooking: Object
  },
  data() {
    return {
      isLoading: false,
      projects: [],
      projectTasks: [],
      tasks: [],
      bookingType: 'PD',
      bookingData: {
        projectId: '',
        taskId: '',
        bookingStartDate: '',
        bookingEndDate: '',
        hours: 0,
        minutes: 0,
        specificStartTime: '',
        specificStopTime: '',
        description: '',
        resourceId: null,
        workingOnOffDays: '',
        taskType: 0
      },
      errors: {},
      hasLoadedProjects: false
    };
  },
  created() {
      // Load projects once when component is created
      this.FetchProjectTaskData();
  },
  watch: {
    showPopup(val) {
      if (val) {
        this.initializePopup();
      }
    }
  },
  methods: {
    async initializePopup() {
      debugger;
      //await this.FetchProjectTaskData();
      
      if (this.isEditMode && this.existingBooking) {
        this.populateEditData();
      } else {
        this.resetForm();
        this.bookingData.resourceId = this.cellData.userId;
        this.bookingData.bookingStartDate = this.formatDateForInput(this.cellData.date);
        this.bookingData.bookingEndDate = this.formatDateForInput(this.cellData.date);
      }
    },

    async FetchProjectTaskData() {
  debugger;

  if (this.hasLoadedProjects) {
    console.log('Projects already loaded, skipping API call');
    return;
  }

  this.isLoading = true;

  try {
    const response = await DataService.GetProjectTaskData();
    console.log('API response:', response);

    if (response.data && response.data.length > 0) {
      // Store full dataset for task lookup
      this.projectTasks = response.data;

      // Extract unique projects
      const seen = new Set();
      this.projects = response.data.reduce((acc, item) => {
        if (!seen.has(item.projectId)) {
          seen.add(item.projectId);
          acc.push({
            projectId: item.projectId,
            projectName: item.projectName
          });
        }
        return acc;
      }, []);

      this.hasLoadedProjects = true;

    } else {
      this.projects = [];
      this.projectTasks = [];
      this.ShowAlert(this.$t('NoProjectsFound'), 'warning', true, this.$t('Alert'));
    }
  } catch (error) {
    this.ShowAlert(this.$t('FailedToLoadProjects'), 'error', true, this.$t('Alert'));
  } finally {
    this.isLoading = false;
  }
},

onProjectChange() {
  debugger;
  this.tasks = [];
  this.bookingData.taskId = '';

  if (!this.bookingData.projectId) return;

  console.log('Selected project ID:', this.bookingData.projectId);

  // Filter tasks from full dataset
  const filtered = this.projectTasks.filter(
    item => item.projectId == this.bookingData.projectId
  );

  this.tasks = filtered.map(item => ({
    taskId: item.taskId,
    taskName: item.taskName,
    tStartDate: item.tStartDate,
    tEndDate: item.tEndDate
  }));

},

    populateEditData() {
  debugger;
  const booking = this.existingBooking;
  this.bookingData = {
    projectId: booking.project_id,
    taskId: booking.task_Id,
    bookingStartDate: this.formatDateForInput(booking.booking_start_date),
    bookingEndDate: this.formatDateForInput(booking.booking_end_date),
    hours: Math.floor(booking.per_day_working_hours / 60),
    minutes: booking.per_day_working_hours % 60,
    specificStartTime: booking.specific_start_time ? this.formatTimeForInput(booking.specific_start_time) : '',
    specificStopTime: booking.specific_stop_time ? this.formatTimeForInput(booking.specific_stop_time) : '',
    description: booking.description || '',
    resourceId: booking.resource_id,
    workingOnOffDays: booking.working_on_off_days || '',
    taskType: booking.task_type || 0
  };

  this.bookingType = booking.specific_start_time ? 'ST' : 'PD';
  
  // Load tasks for the selected project
  this.onProjectChange();
},

    resetForm() {
      this.bookingData = {
        projectId: '',
        taskId: '',
        bookingStartDate: '',
        bookingEndDate: '',
        hours: 0,
        minutes: 0,
        specificStartTime: '',
        specificStopTime: '',
        description: '',
        resourceId: null,
        workingOnOffDays: '',
        taskType: 0
      };
      this.bookingType = 'PD';
      this.errors = {};
    },

    validateForm() {
      this.errors = {};
      
      if (!this.bookingData.projectId) this.errors.projectId = this.$t('ProjectRequired');
      if (!this.bookingData.taskId) this.errors.taskId = this.$t('TaskRequired');
      if (!this.bookingData.bookingStartDate) this.errors.bookingStartDate = this.$t('StartDateRequired');
      if (!this.bookingData.bookingEndDate) this.errors.bookingEndDate = this.$t('EndDateRequired');
      
      if (this.bookingType === 'PD') {
        if (this.bookingData.hours === 0 && this.bookingData.minutes === 0) {
          this.errors.hours = this.$t('HoursOrMinutesRequired');
        }
      } else {
        if (!this.bookingData.specificStartTime) this.errors.specificStartTime = this.$t('StartTimeRequired');
        if (!this.bookingData.specificStopTime) this.errors.specificStopTime = this.$t('EndTimeRequired');
      }

      return Object.keys(this.errors).length === 0;
    },

    async saveBooking() {
      //debugger;
      if (!this.validateForm()) return;

      const project = this.projects.find(p => p.projectId == this.bookingData.projectId);
      const task = this.tasks.find(t => t.taskId == this.bookingData.taskId);

      // Calculate total minutes for hours display
      const totalMinutes = (this.bookingData.hours * 60) + this.bookingData.minutes;

      // Ensure resourceId is properly set
      const resourceId = this.bookingData.resourceId || (this.cellData && this.cellData.userId);

      // Emit booking info to parent with proper structure
      this.$emit("bookingPreviewAdded", {
        resourceId: resourceId,
        date: this.cellData.date,
        startDate: this.bookingData.bookingStartDate,
        endDate: this.bookingData.bookingEndDate,
        projectId: this.bookingData.projectId,
        projectName: project ? project.projectName : "",
        taskId: this.bookingData.taskId,
        taskName: task ? task.taskName : "",
        hours: totalMinutes,
        description: this.bookingData.description,
        bookingType: this.bookingType
      });

      this.closePopup();
},

    async deleteBooking() {
      debugger;
      var vueObj = this;
      
      vueObj.confirmR(vueObj.$t("ConfirmDelete"), true, (vueObj.$t("Delete") + " " + vueObj.$t("Booking")), async function () {
        vueObj.isLoading = true;
        
        try {
          var obj = {
            bookingId: vueObj.existingBooking.booking_id,
            resourceId: vueObj.bookingData.resourceId
          };
          
          var objectPostString = JSON.stringify(obj);
          
          // Using DataService pattern from your sample
          await DataService.DeleteBooking(objectPostString).then(function (response) {
            debugger;
            if (response.data.result && response.data.result.DATA && response.data.result.DATA[0].VALUE == 'SUCCESS') {
              vueObj.ShowAlert(vueObj.$t('DeletedSuccess', [vueObj.$t('Booking')]), "success", true, vueObj.$t("Alert"));
              vueObj.$emit('deleted', response.data);
              vueObj.closePopup();
            } else {
              vueObj.ShowAlert(vueObj.$t('DeletedError', [vueObj.$t('Booking')]), "error", true, vueObj.$t("Alert"));
            }
          });
        } catch (error) {
          vueObj.ShowAlert(vueObj.$t('FailedToDeleteBooking'), "error", true, vueObj.$t("Alert"));
        } finally {
          vueObj.isLoading = false;
        }
      });
    },

    async checkTaskHours() {
      debugger;
      if (!this.bookingData.taskId) return;
      
      var vueObj = this;
      var totalMinutes = (vueObj.bookingData.hours * 60) + vueObj.bookingData.minutes;
      
      try {
        var params = `taskId=${vueObj.bookingData.taskId}&hour=${totalMinutes}`;
        
        // Using DataService pattern from your sample
        await DataService.CheckTaskHours(params).then(function (response) {
          debugger;
          if (response.data && response.data.result && response.data.result > 0) {
            var taskHours = new Date(response.data.result * 1000).toISOString().substr(11, 5);
            vueObj.ShowAlert(vueObj.$t('AssignedHourMessage', [taskHours]), "warning", true, vueObj.$t("Alert"));
          }
        });
      } catch (error) {
        console.error('Failed to check task hours:', error);
      }
    },

    closePopup() {
      this.$emit('close');
    },

    formatDateForInput(epochTime) {
      if (!epochTime) return '';
      return new Date(parseInt(epochTime)).toISOString().split('T')[0];
    },

    formatTimeForInput(epochTime) {
      if (!epochTime) return '';
      return new Date(parseInt(epochTime)).toTimeString().slice(0, 5);
    },

    confirmR(message, isConfirm, title, callback) {
      if (window.confirm(message)) {
        callback();
      }
    },

    ShowAlert(message, type, show, title) {
      alert(`${title}: ${message}`);
    }
  }
};
</script>

<style scoped>
.booking-popup-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0,0,0,0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.booking-popup {
  background: white;
  border-radius: 8px;
  width: 90%;
  max-width: 600px;
  max-height: 90vh;
  overflow-y: auto;
}

.popup-header {
  padding: 1rem;
  border-bottom: 1px solid #dee2e6;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.popup-content {
  padding: 1rem;
}

.popup-footer {
  padding: 1rem;
  border-top: 1px solid #dee2e6;
  display: flex;
  gap: 0.5rem;
  justify-content: flex-end;
}

.required {
  color: red;
}

.error {
  color: red;
  font-size: 0.875rem;
}

.radio-group {
  display: flex;
  gap: 1rem;
}

.radio-group label {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.close-btn {
  background: none;
  border: none;
  font-size: 1.5rem;
  cursor: pointer;
}

.btn {
  padding: 0.5rem 1rem;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

.btn-primary {
  background-color: #007bff;
  color: white;
}

.btn-secondary {
  background-color: #6c757d;
  color: white;
}

.btn-danger {
  background-color: #dc3545;
  color: white;
}

.btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}
</style>