<template>
        <div class="my-popups">
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered modal-lg">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full d-flex">
                        <h4 class="modal-title">Projects / Task Details </h4> 
                      
                        <!-- - {{ user.userName }} -->
                        <button type="button" class="close" v-on:click="showProjectTaskDetails">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <div class="table-responsive">
                            <table class="table table-sm">
                                <thead class="thead-light text-center">
                                    <tr>
                                        <th>{{ $t('ProjectName') }}</th>
                                        <th>{{ $t('TaskName') }}</th>
                                        <th>{{ $t('WorkingHours') }}</th>
                                        <th>{{ $t('LeaveQuantity') }}</th>
                                    </tr>
                                </thead>
                                <tbody class=text-center>
                                    <tr v-for="(task, index) in TaskData.data.bookings" :key="index">
                                        <td>{{ task.project_name || '--' }}</td>
                                        <td>{{ task.task_name || '--' }}</td>
                                        <td>{{ showhoursPerDay(TaskData.data.shiftHours) || 0 }} </td>
                                        <td>{{ TaskData.data.userLeave || 0 }}</td>
                                    </tr>
                                   <tr v-if="TaskData.length === 0">
                                      <td colspan="4" class="text-center text-danger">
                                         {{$t("NoRecordfound")}}
                                      </td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>
                    <div class="modal-footer">
                        <button type="button" class="btn btn-danger" v-on:click="showProjectTaskDetails">
                            Close
                        </button>
                    </div>
                </div>
            </div>
        </div>
    </div>
    </template>

    <script>
export default{
    props:{
        TaskData:{
            type:Array | Object,
            required:true
        }
    },
    data() {
        return {
        }
    },
    methods:{
        showProjectTaskDetails(){
            this.$parent.IsTaskDetail=false;
        },
        showhoursPerDay: function (value) {
            value=value * 60;
           var hours = Math.floor(value / 60);
            value %= 60;
           var  minutes = Math.floor(value % 60);
            if (minutes < 10)
                minutes = '0' + minutes;
            return hours + 'H : ' + minutes + 'M';
        },
        
    }
}

</script>