<template lang="en">
<section>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full d-flex">
                        <h4 class="modal-title">{{ $t('ManageTentativeLeave') }} - {{TentativeLeaveData.userName}}</h4> 
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext="MandatoryString">
                        </dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</section>
</template>
<script>
export default {
    props: {
        TentativeLeaveData: {
            type: Object,
            required: true
        }
    },
    data() {
        return {
            isLoading: false,
            FormSchema: [{
                    layoutType: "double",
                    Data: [{
                            astype: "DateField",
                            label: this.$t('Start Date (DD/MM/YYYY)'),
                            name: "StartDate",
                            value: new Date(),
                            placeholder: this.$t('Start Date'),
                            config: {
                                format: "M/D/YYYY",
                                minDate: new Date()
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('End Date (DD/MM/YYYY)'),
                            name: "EndDate",
                            value: new Date(),
                            placeholder: this.$t('End Date'),
                            config: {
                                format: "M/D/YYYY",
                                minDate: new Date()
                            }
                        }
                    ]
                },
                {
                    layoutType: "single",
                    Data: [{
                        astype: "RadioField",
                        label: this.$t('Type'),
                        name: "Type",
                        value: "FL",
                        placeholder: "",
                        config: {
                            options: [{
                                value: "SL",
                                name: "Short Leave"
                            }, {
                                value: "HL",
                                name: "Half Day Leave"
                            }, {
                                value: "FL",
                                name: "Full-Day Leave"
                            }]
                        },
                        visibility: true
                    }]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                }
            ]
        }
    },
    created() {
        var vm = this;
        vm.UserId = vm.TentativeLeaveData.userId;
        if(vm.TentativeLeaveData.userTentativeLeave != null){
            
        }else{

        }
    },
    methods: {
        onSubmit: function (formFields) {            
            var vm = this;
            var startDateInput= formFields.StartDate;
            var endDateInput= formFields.EndDate;
            const startDateObj = new Date(startDateInput);
            const endDateObj = new Date(endDateInput);
            if (startDateObj > endDateObj) {                
                vm.ShowAlert(vm.$t("PlanStartDateLessThanEndDate"), "warning", true, vm.$t("Alert"));
                return false;
            }
            let startDate = new Date(startDateInput);
            let endDate = new Date(endDateInput);
            startDate.setHours(0, 0, 0, 0);
            endDate.setHours(0, 0, 0, 0);
            const UserId = vm.TentativeLeaveData.userId;
            if (startDate.getTime() === endDate.getTime()) {
                const dataArray = [];
                const obj = {
                    StartDate: new Date(startDateInput),
                    EndDate: new Date(endDateInput),
                    Type: formFields.Type,
                    UserId: UserId,
                    StatusId: 1001
                };
                dataArray.push(obj);
                vm.$emit('ApplyTentaiveLeave',vm.UserId,dataArray)
            }
            else{
                const dataArray = [];
                const days = vm.NoOfDays(startDate, endDate);
                for (let i = 0; i < days; i++) {
                    const loopDate = new Date(startDate);
                    loopDate.setDate(loopDate.getDate() + i);
                    const obj = {
                        StartDate: loopDate,
                        EndDate: loopDate,
                        Type: formFields.Type,
                        UserId: UserId,
                        StatusId: 1001
                    };
                    dataArray.push(obj);
                }
                if (dataArray.length > 0) {                    
                    vm.$emit('ApplyTentaiveLeave',vm.UserId,dataArray)
                }                
            } 
            vm.ShowAlert(vm.$t("AddedSuccess",[vm.$t("TentativeLeave")]),"success",true,vm.$t("Alert"));
            vm.Close();           
        },  
        NoOfDays(firstDate,secondDate) {
            const oneDay = 24 * 60 * 60 * 1000; 
            const diffDays = Math.round(Math.abs((firstDate - secondDate) / oneDay));
            return Number(diffDays) + 1;
        },      
        Close: function () {
            this.$emit('CloseTentativeLeave');
        }
    }
}
</script>