<script>
import DataService from '../../../services/DataService';
export default {
    data() {
        return {
            isLoading: false,
            IsCostCentre: '',
            IsDepartment: '',
            IsProject: [],
            IsChooseShift: '',
            txtsearchuser: '',
            txtsearchprojectuser:'',
            CostCentreData: [],
            DepartmentData: [],
            ProjectData: [],
            ChooseShiftData: [],
            UserData: [],
            ProjectUser:[],
            originalUserData: [],
            selectedUsers: [],
            selectAll: false,
            selectAll1:false
        }
    },
    created: function () {
        var ths = this;
        ths.GetCompanyLocation();
        ths.GetDepartment();
        ths.GetProjectTaskData();
        ths.GetCompanyLocationWithShift();
    },
    methods: {
        GetCompanyLocation() {
            var ths = this;
            ths.CostCentreData=[];
            DataService.GetCompanyLocation().then(res => {
                if (res.data.length > 0) {
                    ths.CostCentreData = res.data;
                }
            })
        },
        GetDepartment: function () {
            var ths = this;
            ths.DepartmentData=[];
            var url = `id=&moduleName=&type=DEPARTMENT_TYPE&search=&refId=`;
            DataService.GetDDLData(url).then((response) => {
                if (response.data.DATA.length > 0) {
                    response.data.DATA.forEach((item) => {
                        let obj = {
                            label: item.name,
                            value: item.value
                        }
                        ths.DepartmentData.push(obj)
                    })
                }
            })
        },        
        GetCompanyLocationWithShift: function () {
            var ths = this;
            ths.ChooseShiftData=[];
            var url = `id=&moduleName=&type=USER_SHIFT_WITH_LOCATION&search=&refId=`;
            DataService.GetDDLData(url).then((response) => {
                if (response.data.DATA.length > 0) {
                    response.data.DATA.forEach((item) => {
                        let obj = {
                            label: item.name,
                            value: item.value
                        }
                        ths.ChooseShiftData.push(obj)
                    })
                }
            })
        },
        GetProjectTaskData: function () {
            var ths = this;
            ths.ProjectData=[];
            DataService.GetProjectTaskData().then((response) => {
                if (response.data.length > 0) {
                    var PData = response.data;
                    const groupedData = PData.reduce((acc, item) => {
                        const projectId = item.projectId;
                        if (!acc[projectId]) {
                            acc[projectId] = {
                                ProjectId: projectId,
                                ProjectName: item.projectName || '',
                                StartDate: new Date(item.startDate).getTime(),
                                EndDate: new Date(item.endDate).getTime(),
                                IsAllowed: item.isAllowed || false,
                                TaskList: []
                            };
                        }
                        acc[projectId].TaskList.push({
                            StartDate: item.tStartDate ? new Date(item.tStartDate).getTime() : 0,
                            EndDate: item.tEndDate ? new Date(item.tEndDate).getTime() : 0,
                            TaskName: item.taskName || '',
                            TaskId: item.taskId || ''
                        });
                        return acc;
                    }, {});                    
                    var NewProjectData = Object.values(groupedData);  
                    NewProjectData.forEach((item) => {
                        let obj = {
                            label: item.ProjectName,
                            value: item.ProjectId
                        }
                        ths.ProjectData.push(obj)
                    })                  
                    
                }
            });
        },
        GetShiftByLocation(){
            var ths = this;
            var url = `id=&moduleName=&type=USER_SHIFT_WITH_LOCATION_ID_PROJECT&search=&refId=${ths.IsCostCentre}`;
            DataService.GetDDLData(url).then((response) => {
                if (response.data.DATA.length > 0) {
                    ths.ChooseShiftData=[];
                    response.data.DATA.forEach((item) => {
                        let obj = {
                            label: item.name,
                            value: item.value
                        }
                        ths.ChooseShiftData.push(obj)
                        ths.BindUserDDL();
                    })
                }
            })
        },
        GetUserByProjectId()
        {
            debugger
           var vm=this;
           vm.UserData = [];
           vm.originalUserData=[];
           vm.isLoading=true;
           const projectIds = vm.IsProject.map(p => p.value).join(',');
           if(projectIds=='' || projectIds ==null)
           {
            vm.ProjectUser = [];
             vm.originalUserData=[];
             vm.isLoading=false;
            return;
           }
           var url=`departmentId=&projectId=${projectIds}`;
           DataService.GetPMUserList(url).then((response)=>{
            if (response.data.length > 0) {
                vm.originalUserData = response.data;
                vm.ProjectUser = response.data;     
            }
            vm.isLoading=false;
           });

        },
        BindUserDDL() {
            var ths = this;
            ths.UserData=[];
            ths.originalUserData=[];
            ths.isLoading=true;
            if (ths.IsChooseShift != "" || ths.IsCostCentre > 0 || ths.IsDepartment != '') {
                var url=`locationId=${ths.IsCostCentre}&shiftId=${ths.IsChooseShift}&deptIds=${ths.IsDepartment}`;
                DataService.BindUserDDL(url).then(res => {

                    if (res.data.length > 0) {
                        ths.originalUserData = res.data;
                        ths.UserData = res.data;
                    }
                    ths.isLoading=false;
                })
            }

        },
        SearchUser() {
            if (this.txtsearchuser.trim() !== '' || this.txtsearchprojectuser.trim() !=='') {
               if(this.UserData.length>0)
               {
                this.UserData = this.originalUserData.filter(user =>
                    user.userName.toLowerCase().includes(this.txtsearchuser.toLowerCase()));}
               else{
                this.ProjectUser = this.originalUserData.filter(user =>
                user.userName.toLowerCase().includes(this.txtsearchprojectuser.toLowerCase()));}
            } else {
                if(this.UserData.length>0)
                {
                this.UserData = this.originalUserData;
                }
                else{
                    this.ProjectUser = this.originalUserData;
                }
            }
        },
        ResetSearch() {
            this.txtsearchuser = '';
            this.txtsearchprojectuser='';
             if( this.UserData.length > 0)
             {
                this.UserData = this.originalUserData;
             }
             else
             {
                this.ProjectUser = this.originalUserData;
             }
            this.selectedUsers = [];
            this.selectAll = false;
            this.selectAll1 = false;            
        },
        toggleSelectAll() {
            this.selectAll = !this.selectAll;
            this.selectAll1 = !this.selectAll1;
            if (this.selectAll || this.selectAll1) {
                if(this.UserData.length > 0)
            {
                this.selectedUsers = this.UserData.map(user => user.userId);
            }
            else{
                this.selectedUsers = this.ProjectUser.map(user => user.userId);
            }

            } else {
                this.selectedUsers = [];
            }
        },
        toggleUserSelection(userId) {
            const index = this.selectedUsers.indexOf(userId);
            if (index > -1) {
                this.selectedUsers.splice(index, 1);
            } else {
                this.selectedUsers.push(userId);
            }
            this.selectAll = this.UserData.length > 0 && this.selectedUsers.length === this.UserData.length;
            this.selectAll1 = this.ProjectUser.length > 0 && this.selectedUsers.length === this.ProjectUser.length;
        },
        CloseResourceFilter: function () {
            //this.$emit('CloseResourceFilter');
            this.$router.push({ name: 'ProjectList' });
        },
        SearchResource(){
            //debugger
           if(this.IsCostCentre!="" || this.IsProject!="" )
           {
            this.isLoading=true;
            if(this.selectedUsers.length > 0)
            {
            var Obj={
                IsCostCentre:this.IsCostCentre,
                IsDepartment:this.IsDepartment,
                IsChooseShift:this.IsChooseShift,
                selectedUsers:this.selectedUsers
            };
            this.$emit('AllSearchResource',Obj);
           }
           else{
            this.isLoading=false;
            this.ShowAlert(this.$t("PleaseSelectAtleastOneUser"), "failure", true, this.$t('Alert'));
           }
           }
           else{
           this.ShowAlert(this.$t("MandatoryString"), "failure", true, this.$t('Alert'));
           }
        },
        ResetFields()
        {
          var ths = this;
          ths.UserData=[];
          ths.ProjectUser=[];
          ths.originalUserData=[];
          ths.selectedUsers=[];
          ths.txtsearchuser='';
          ths.IsCostCentre="";
          ths.IsProject="";
          ths.selectAll= false;
          ths.selectAll1=false;
          ths.txtsearchprojectuser='';
          ths.ResetSearch();
          ths.GetCompanyLocation();
          ths.GetDepartment();
          ths.GetProjectTaskData();
          ths.GetCompanyLocationWithShift();
        },
    }
}
</script>

