<template>

   <section class="res-section m-0">
      <loader :is-visible="isLoading"></loader>
      <header class="hs">
         <nav class="date-controls">
            <table width="100%" cellpadding="0" cellspacing="0" border="0">
               <tbody>
                  <tr>
                     <td class="text-right"><a class="current" href="javascript:;" @click.prevent="goToToday()">Today</a></td>
                     <td class="text-right">
                        <div class="btn-group">
                           <a title="" class="btn previous" href="javascript:;" @click.prevent="previousWekDayMonth()"
                              data-toggle-tooltip="tooltip" data-original-title="Previous"><i
                                 class="fa fa-chevron-left"></i></a> 
                           <a title="" class="btn next" href="javascript:;" @click.prevent="nextWekDayMonth()"
                              data-toggle-tooltip="tooltip" data-original-title="Next"><i
                                 class="fa fa-chevron-right"></i></a> </div>
                     </td>
                  </tr>
                  <tr class="border-top">
                     <td width="45%" class="text-right bodnone d-none" valign="top">
                        <ul class="zoom">
                           <li class="zoom__daily selectedd"><a title="" href="javascript:;"
                                 data-toggle-tooltip="tooltip" data-original-title="Daily"><span>&nbsp;</span></a></li>
                           <li class="zoom__detailed"><a title="" href="javascript:;" data-toggle-tooltip="tooltip"
                                 data-original-title="Detailed"><span>&nbsp;</span></a></li>
                        </ul>
                     </td>
                     <td width="100%" colspan="2" class="text-left">
                        <ul class="zoom">
                           <li title="Switch User" id="btnSwitch" class="switch_users" @click="switchUsers"><a href="javascript:;"
                                 class="btn btn-primary"><em class="fa fa-user-plus pr-2" ></em>Switch User</a></li>
                           <li class="save_res"><a id="btnSave" title="" href="javascript:;"
                                 class="btn btn-success ml-1" data-toggle-tooltip="tooltip"
                                 data-original-title="Save" @click="saveResourceData"><i class="fa fa-save pr-2"></i>Save</a></li>
                           <li class="Expand"><a class="expandAll" title=""
                                 style="background-image: none;outline: none;" href="javascript:;"
                                 data-toggle-tooltip="tooltip" data-original-title="Collapse All"><i
                                    class="fa fa-chevron-down"></i></a></li>
                        </ul>
                     </td>
                  </tr>
               </tbody>
            </table>
         </nav>




         <div id="time-periods" :style="{ width: totalHeaderWidth + 'px' }">
            <div v-for="(period, index) in timePeriods" :key="index" class="unit-group"
               :data-first-date="period.firstDateFormatted" :data-last-date="period.lastDateFormatted">
               <h2 v-if="currentView == 'week'">
                  {{ period.label }}
                  <span style="float:right;">Week: {{ period.week }}</span>
               </h2>
               <h2 v-else-if="currentView == 'Month'" class="text-center" style="justify-content:center;">
                     {{ period.label }}
               </h2>
               <h2 v-else class="text-center" style="justify-content:center;">
                     {{ period.label }}
               </h2>
               <div class="units">
                  <div v-for="(unit, idx) in period.days" :key="idx" class="cal-unit"
                     :class="{ current: unit.isCurrent }" :data-date="unit.dataDate" :style="{ width: columnWidth + 'px' }">
                     <span class="dname">{{ unit.dayName }}</span>
                     <span class="ddate">{{ unit.dateNum }}</span>
                  </div>
               </div>
            </div>
         </div>
      </header>
   </section>
</template>

<script>
import DataService from '../../../services/DataService';

export default {
   name: 'SchedulerHeader',
   props: {
      fromDate: Date,
      toDate: Date,
      currentView: String,
      resources: Array,
      readonly: Boolean,
      offday:String
   },
   data() {
      return {
         isLoading:false,
         updatedRecords:[],
         Fromdate: '',
         Enddate: ''
      }
   },
   computed: {
      columnWidth() {
         // Column width based on view - must match ResourceList plotWidth
         if (this.currentView === 'Day') {
            return 170; // Wider columns for day view
         }
         if (this.currentView === 'Month') {
            return 40.1; // Wider columns for day view
         }
         return 40; // Standard width for week and month views
      },
      totalHeaderWidth() {         
         let totalDays = 0;
         this.timePeriods.forEach(period => {
            totalDays += period.days.length;
         });
         return (totalDays * this.columnWidth) + 20;
      },
      timePeriods() {
         const start = new Date(this.fromDate);
         const end = new Date(this.toDate);
         const periods = [];
         if (this.currentView === 'Month') {
            const startMonth = new Date(start.getFullYear(), start.getMonth(), 1);
            const endMonth = new Date(end.getFullYear(), end.getMonth() + 1, 0);
            const currentMonth = new Date(startMonth);
            while (currentMonth <= endMonth) {
               const monthStart = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1);
               const monthEnd = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0);
               const days = [];
               for (let d = new Date(monthStart); d <= monthEnd && d <= end; d.setDate(d.getDate() + 1)) {
                  days.push({
                     date: d.toISOString(),
                     dateNum: d.getDate(),
                     dayName: d.toLocaleDateString("en-US", { weekday: "short" }),
                     isToday: new Date().toDateString() === d.toDateString()
                  });
               }
               if (days.length > 0) {
                  periods.push({
                     label: `1 - ${monthEnd.getDate()} ${monthStart.toLocaleString("default", { month: "short" })} ${monthStart.getFullYear()}`,
                     week: this.getWeekNumber(monthStart),
                     days
                  });
               }
               currentMonth.setMonth(currentMonth.getMonth() + 1);
            }
         } else if (this.currentView === 'Day') {
            // Day view: Show all days individually, grouped by weeks for display headers only
            const allDays = [];
            const currentDate = new Date(start);
            while (currentDate <= end) {
               allDays.push({
                  date: new Date(currentDate).toISOString(),
                  dateNum: currentDate.getDate(),
                  dayName: currentDate.toLocaleDateString("en-US", { weekday: "short" }),
                  isToday: new Date().toDateString() === currentDate.toDateString()
               });
               currentDate.setDate(currentDate.getDate() + 1);
            }
            
            // Group days by weeks for display headers
            if (allDays.length > 0) {
               for (let i = 0; i < allDays.length; i += 7) {
                  const weekDays = allDays.slice(i, i + 7);
                  if (weekDays.length > 0) {
                     const firstDay = new Date(weekDays[0].date);
                     const lastDay = new Date(weekDays[weekDays.length - 1].date);
                     periods.push({
                        label: firstDay.getMonth() === lastDay.getMonth()
                           ? `${firstDay.getDate()} - ${lastDay.getDate()} ${firstDay.toLocaleString("default", { month: "short" })} ${firstDay.getFullYear()}`
                           : `${firstDay.getDate()} ${firstDay.toLocaleString("default", { month: "short" })} - ${lastDay.getDate()} ${lastDay.toLocaleString("default", { month: "short" })} ${lastDay.getFullYear()}`,
                        week: this.getWeekNumber(firstDay),
                        days: weekDays
                     });
                  }
               }
            }
         } else {
            // Week view: Group days by weeks
            const diffWeeks = Math.ceil((end - start) / (7 * 24 * 60 * 60 * 1000));
            for (let i = 0; i < diffWeeks; i++) {
               const first = new Date(start);
               first.setDate(start.getDate() + i * 7);
               let last = new Date(first);
               last.setDate(first.getDate() + 6);
               if (last > end) {
                  last = new Date(end);
               }
               const days = [];
               for (let j = 0; j < 7; j++) {
                  const d = new Date(first);
                  d.setDate(first.getDate() + j);
                  if (d <= end) {
                     days.push({
                        date: d.toISOString(),
                        dateNum: d.getDate(),
                        dayName: d.toLocaleDateString("en-US", { weekday: "short" }),
                        isToday: new Date().toDateString() === d.toDateString()
                     });
                  }
               }
               if (days.length > 0) {
                  periods.push({
                     label: first.getMonth() === last.getMonth()
                        ? `${first.getDate()} - ${last.getDate()} ${first.toLocaleString("default", { month: "short" })} ${first.getFullYear()}`
                        : `${first.getDate()} - ${last.getDate()} ${last.toLocaleString("default", { month: "short" })} ${last.getFullYear()}`,
                     week: this.getWeekNumber(first),
                     days
                  });
               }
            }
         }
         return periods;
      }
   },
   created: function () {
    //debugger
    var ths = this;
  },
  mounted() {

   debugger
  this.$root.$on('call-UpdateRecrds', (payload) => {
   if (payload.action === 'update' || payload.action ===  'create') {
      this.updateRecords(payload.booking);
    }
  });
},
beforeDestroy() {
  this.$root.$off('call-UpdateRecrds');
},
   methods: {
      getWeekNumber(d) {
         const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
         const dayNum = date.getUTCDay() || 7;
         date.setUTCDate(date.getUTCDate() + 4 - dayNum);
         const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
         return Math.ceil(((date - yearStart) / 86400000 + 1) / 7);
      },
      previousWekDayMonth() {
         this.$emit('navigate', { direction: 'prev', view: this.currentView });
      },
      nextWekDayMonth() {
         this.$emit('navigate', { direction: 'next', view: this.currentView });
      },
      goToToday() {
         this.$emit('navigate', { direction: 'today', view: this.currentView });
      },
      switchUsers()
      {
         
            var vm = this;
          vm.$emit('switchuser');
      },
    updateRecords(data) {
      
      const existIndex = -1;
       if (!this.updatedRecords) {
         existIndex  = this.updatedRecords.findIndex(
          item => item.booking_id === data.booking_id
       );
       }       
       const formattedBooking = {
          booking_id: data.booking_id,
          resource_id: data.resource_id,
          project_id: data.project_id || null,
          task_Id: data.task_Id || null,
          description: data.description || "",
          start_date: this.formatDateForAPI(data.booking_start_date),
          end_date: this.formatDateForAPI(data.booking_end_date),
          specific_day_start_time: data.specific_start_time?data.specific_start_time: null,
          specific_day_stop_time: data.specific_stop_time ? data.specific_stop_time: null,
          per_day_working_hours: data.per_day_working_hours || 0,
          working_on_off_days: data.working_on_off_days || false,
          total: data.total || 0,
          is_change: data.is_change || false,
          task_type: data.task_type 
       }
       if (existIndex  !=-1) {
          this.$set(this.updatedRecords, existIndex, formattedBooking);
       } else {
          this.updatedRecords.push(formattedBooking);
       }
       const resourceData = {
            bookings: formattedBooking,
            tentativeLeave: []
         };
         this.saveToAPI(resourceData);
       },
      saveResourceData() {
         var vm = this;
         const allTentativeLeaves = [];
         const allBookings = [];
         let bookingCounter = -1;
         vm.resources.forEach(resource => {
            if (resource.userTentativeLeave && Array.isArray(resource.userTentativeLeave)) {
               resource.userTentativeLeave.forEach(leave => {
                  allTentativeLeaves.push({
                     userId: resource.userId,
                     StartDate: this.formatDateForAPI(leave.StartDate),
                     EndDate: this.formatDateForAPI(leave.EndDate),
                     Type: leave.Type,
                     StatusId: leave.StatusId
                  });
               });
            }
            if (resource.bookings && Array.isArray(resource.bookings)) {
               resource.bookings.forEach((booking) => {
                  debugger
                  if (!booking) return;
                  if (booking.booking_id === 0) {
                        allBookings.push({
                        booking_id: bookingCounter--,
                        resource_id: resource.userId,
                        project_id: booking.project_id || 0,
                        task_Id: booking.task_Id || 0,
                        description: booking.description || "",
                        start_date: this.formatDateForAPI(booking.booking_start_date),
                        end_date: this.formatDateForAPI(booking.booking_end_date),
                        specific_day_start_time: booking.specific_start_time
                           ? this.formatDateForAPI(booking.specific_start_time)
                           : null,
                           specific_day_stop_time: booking.specific_stop_time
                           ? this.formatDateForAPI(booking.specific_stop_time)
                           : null,
                        
                        per_day_working_hours: booking.per_day_working_hours || 0,
                        working_on_off_days: booking.working_on_off_days =='No' ? false : true,
                        total: booking.total || 0,
                        is_change: booking.is_change == 0 ? false :true,
                        task_type: booking.task_type == 0 ? false :true 
                        });
                     }
                  });
               }
         });
         const resourceData = {
            bookings: allBookings,
            tentativeLeave: allTentativeLeaves
         };
         vm.saveToAPI(resourceData);
      },
      async saveToAPI(resourceData) {
         debugger
         this.isLoading=true;
         try {
            console.log("Sending to API:", resourceData);
            const params = {
               tblResources: resourceData.bookings,
               LEAVE_JSON:JSON.stringify(resourceData.tentativeLeave)
            };
           
            const response = await DataService.SaveResourceScheduling(params);            
            if (response.data.msg === "SUCCESS") {
               
               this.isLoading=false;
               this.$emit('save-completed', true);
               this.ShowAlert(this.$t("AddedSuccess",[this.$t("ResourceScheduling")]),"success",true,this.$t("Alert"));        
              
            } 
            else if(response.data.msg === "EXIST")
            {
              this.isLoading=false;
              this.$emit('save-completed', true);
              this.ShowAlert(this.$t("AlreadyExists",[this.$t("ResourceScheduling")]),"failure",true,this.$t("Alert"));         
              // Also emit completion so parent can react (e.g., reload/keep UI in sync)              
            }
            else {
                  this.isLoading=false;
                  this.$emit('save-completed', false);
                  this.ShowAlert(this.$t("AddedError",[this.$t("ResourceScheduling")]),"failure",true,this.$t("Alert"));
                  
            }
         } 
         catch (error) {
            console.error("Error saving resource scheduling:", error);
            this.showErrorMessage("Error saving resource scheduling.");
            this.$emit('save-completed', false);
         }
      },

      showSuccessMessage(message) {         
         alert(message); 
      },

      showErrorMessage(message) {         
         alert(message); 
      },

      formatDateTimeForAPI(date) {
         if (!date) return null;
         const d = new Date(date);
         const year = d.getFullYear();
         const month = String(d.getMonth() + 1).padStart(2, '0');
         const day = String(d.getDate()).padStart(2, '0');
         const hours = String(d.getHours()).padStart(2, '0');
         const minutes = String(d.getMinutes()).padStart(2, '0');
         const seconds = String(d.getSeconds()).padStart(2, '0');
         return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}`;
      },
      formatDateForAPI(date) {
         if (!date) return '';
         const d = new Date(date);
         const year = d.getFullYear();
         const month = String(d.getMonth() + 1).padStart(2, '0');
         const day = String(d.getDate()).padStart(2, '0');
         return `${year}-${month}-${day}`;
      },
   }
}
</script>
<style scoped>
.scheduler-header .btn {
   border: 1px solid #ccc;
   padding: 6px 10px;
   border-radius: 6px;
   cursor: pointer;
}
.btn-primary {
   background: #007bff;
   color: #fff;
