<template>
   <div :style="{ height: computedHeight }" class="resource" id="resource">
    <div>
    <div class="initialsbase">{{ getInitials(user.userName) }}</div>
    <h3>{{ user.userName }}</h3>
    <h4>{{ user.departmentName }}</h4>
    <p class="timezone"></p>
    <p class="shift">
      <strong>{{ $t('Shift') }}: </strong>
      <a href="javascript:;" class="changeshift" title="Change Shift">
        {{ user.shiftId != null ? user.shiftName : 'N/A' }}
      </a>
      &nbsp;&nbsp;
      <strong>{{ $t('Hours') }}:
        <span style="color: #e2920b;">
          {{ user.shiftId != null ? user.shiftHours : 'N/A' }}
        </span>
      </strong>
    </p> 
    <div class="w-100 float-left" id="proj_task_data" v-if="showTasks && parsedUserTaskData && parsedUserTaskData.length > 0">
      <div class="work-data mt-2" style="display: block;">
        <div class="d-flex work-int w-100 justify-content-between align-items-center work-task-data" v-for="(item,index) in parsedUserTaskData" :key="index">
          <span>{{ item.TASK_NAME }}<br><small>{{ item.PROJECT_NAME }}</small></span>
          <span class="d-none"><i class="fa fa-calendar"></i></span>
        </div>
        <div class="text-right mt-2 mr-2 project-task">
          <a href="javascript:;" @click="AllUserTaskData(user)" v-if="!user.showAllTasks" class="btn btn-primary project-tasks-all"><em class="fa fa-chevron-down mr-1"></em>Show All</a>
          <a href="javascript:;" @click="HideUserTaskData(user)" v-if="user.showAllTasks" class="btn btn-primary project-tasks-all"><em class="fa fa-chevron-down mr-1"></em>Hide</a>
        </div>
      </div>
    </div>
    <a href="javascript:;" class="downindicator" :title="user.isOpen ? 'Collapse' : 'Expand'">
      <i :class="user.isOpen ? 'fa fa-chevron-up' : 'fa fa-chevron-down'"></i>
    </a>
    <div class="prof_body project-task float-right mr-2">
      <span class="actions mobile-action" style="background:none;">
        <a href="javascript:;" class="float-right action_iconn pt-0" @click="newtoggleOpen()">
          <i class="fa fa-ellipsis-h "></i>
        </a>
        <span class="action-list-box expand" style="opacity: 9;" v-if="user.isOpen"
          :class="user.isOpen ? 'd-block' : 'd-none'" :style="{ opacity: user.isOpen == true ? 9 : 0 }">
          <span class="list-actions fsm-list" id='action-list'>
            <i class="fa fa-times close close-action" aria-hidden="true" @click="newtoggleClose()"></i>
            <!-- <a href="javascript:;" class="actions-onclick clone-schedule" title="Clone Schedule"
                @click="OpenCloneSchedule(user)"><i class="fa fa-copy pr-2" aria-hidden="true"></i><br />Clone
                Schedule</a> 
            -->
            <!-- <a href="javascript:;" class="actions-onclick" title="View Impact"><i
                class="fa fa-area-chart pr-2"></i><br />View Impact</a> -->
            <a href="javascript:;" class="actions-onclick tentative-leave" title="Add Tentative Leave"
              @click="AddTentativeLeave(user)"><em class="fa fa-user-times pr-2 text-danger"></em><br />Add Tentative Leave</a>
          
              <a href="javascript:;" class="actions-onclick project-tasks" title="Projects Task Details"
              @click="handleProjectTaskDetails(user)"><em class="fa fa-file-o pr-2"></em><br />Projects / Task Details</a>  

            <a href="javascript:;" class="actions-onclick project-tasks" title="Task Detail"
              @click="handleProjectTaskDetails(user)"><em class="fa fa-bar-chart pr-2"></em><br />Task Detail</a>

            <a href="javascript:;" class="actions-onclick remove-user" data-userid="110510" @click="RemoveUser(user)"
              title="Remove"><em class="fa fa-close pr-2"></em><br />Remove</a>
          </span>
        </span> 
      </span>
    </div>  


<section class="res-section">
     <div id="resources" class="resource-timeline ml-0" :style="{ marginTop : (user.index == 0 ? 6  : 0) + 'px', width: totalCalendarWidth + 'px' }">
        <div :class="['resource-line', 'colapsableres', { 'dynamictasks': user.bookings && user.bookings.length > 0 }]" :style="{ height: calendarCellHeight }">
          <div
            v-for="(day,dindex) in allDays"
              :key="day.toDateString()"
              class="resources--cal-unit"
              :class="dayClass(day)"
              :style="{ width: plotWidth + 'px', height: calendarCellHeight }"
              :data-day-name="weekdays[day.getDay()]"
              :data-month-name="monthName(day.getMonth())"
              :data-date="day.getTime()"
              @dblclick="onCellDblClick(day, dindex)"
            >
            <!-- UTILIZATION BLOCK -->
            <div class="utilisation" :style="{ height: getUtilizationHeight(day) }" :class="dayClass(day)">
              <div
                v-for="(utilBlock, utilIndex) in getUtilizationBlocks(day)" 
                :key="utilIndex"
                class="unit userschedule clickable-cell" 
                :style="{ width: '100%', marginBottom: '7px', display: 'block' }">
                <span 
                  v-for="(span, spanIndex) in utilBlock.spans" 
                  :key="spanIndex"
                  class="hours text-truncate" 
                  :class="span.class">
                  {{ span.text }}
                </span>
              </div>
            </div>


            <!-- BOOKINGS: use preprocessed bookings for this user -->
            <div
              v-for="(pb, pbIndex) in processedBookingsForUser" :key="pbIndex">             
              <template v-if="dayInRange(day, pb.displayStart, pb.displayEnd)">               
                <div v-if="isSameDay(day, pb.displayStart)" class="bookings draggable">
                    <div class="booking-anchor">
                  <div class="booking-anchor">
                    <div
                      :id="'book-' + pb.booking_id"
                      :class="['booking', 'mine', 'sticky', pb.ColorClass || '', { 'dragging': isDragging && draggedBooking?.booking_id === pb.booking_id, 'resizing': isResizing && resizedBooking?.booking_id === pb.booking_id }]"
                      :style="{ width: pb.Width + 'px', opacity: (isDragging && draggedBooking?.booking_id === pb.booking_id) || (isResizing && resizedBooking?.booking_id === pb.booking_id) ? 0.7 : 1, cursor: readonly ? 'default' : 'move' }"
                      :title="pb.Tooltip"
                      @click.stop="!isDragging && !isResizing && BookingSaveClikc(pb.raw)"
                      @mousedown="onBookingMouseDown($event, pb)"
                      :data-firstday="pb.displayStart"
                      :data-ss_enddate="pb.displayEnd"
                      :data-bookingStartDate="pb.booking_start_date"
                      :data-bookingEndDate="pb.booking_end_date"
                      @click="BookingSaveClikc(pb.raw)"
                      ref="resizeBlock"
                    >
                      <div class="label detailed" style="top:8px;padding-left:0;">
                        {{ pb.project_name }}
                        <template v-if="pb.task_name"> | {{ pb.task_name }}</template>
                        | {{ pb.per_day_working_hours }} Daily | Total {{ pb.total }} Days
                      </div>
                      <div class="label daily" style="top: 6px;line-height:18px; padding-left: 0px;">
                        {{ pb.project_name }} <template v-if="pb.task_name"> | {{ pb.task_name }}</template>
                        | {{ pb.per_day_working_hours }} Daily | Total {{ pb.total }} Days
                      </div>

                      <!-- Resize Handle -->
                      <div 
                        v-if="!readonly"
                        class="resize-handle" 
                        @mousedown.stop="onResizeMouseDown($event, pb)"
                        :title="$t('ResizeTask') || 'Drag to extend task'"
                      ></div>

                     
                    </div>

                    </div>
                  </div>
                        </div>
                <!-- blank cells for other days within the booking range -->
                <div v-else class="bookings blank">
                  <div class="booking-anchor"></div>
                </div>
              </template>
            </div>
            <!-- LEAVE / HOLIDAY / TIME TRACK INDICATORS -->
            <div class="newdiv listing" v-if="leaveType(day)">
              <em :class="leaveType(day).icon" :title="leaveType(day).title"></em>
              <!-- Show leave amount tooltip for approved/pending leaves -->
              <div v-if="leaveType(day).type && (leaveType(day).type === 'LEAVE_APPROVED' || leaveType(day).type === 'LEAVE_PENDING')" 
                   class="popupdiv table-responsive table-fix-header pop-time-data" 
                   style="width:200px;">
                <table class="table table-bordered dt-responsive nowrap mt-0 w-100">
                  <thead class="thead-bg">
                    <tr><th class="width_15">{{ $t('Duration') || 'Duration' }}</th></tr>
                  </thead>
                  <tbody>
                    <tr>
                      <td>
                        <span v-if="leaveType(day).amount == 0.25">{{ $t('SHORT_LEAVE') || '0.25 (Short Leave)' }}</span>
                        <span v-else-if="leaveType(day).amount == 0.5">{{ $t('HALFDAY_LEAVE') || '0.5 (Half Day Leave)' }}</span>
                        <span v-else-if="leaveType(day).amount == 0.75">{{ $t('Three_QUARTER_LEAVE') || '0.75 (Three Quarter Leave)' }}</span>
                        <span v-else>1 ({{ $t('FULLDAY_LEAVE') || 'Full Day Leave' }})</span>
                      </td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
     </div>
</section>
 
 </div>
 </div>
</template>

<script>
import DataService from "../../../services/DataService";
export default {
   
  name: "ResourceList",
  props: {
    user: Object,
    readonly: Boolean,
    fromdate: Date,
    todate: Date,
    currentView: String,
    shifthours: Number,
    showTasks:Boolean
  },
  data() {
    return {      
      isLoading: false,
      showProjectTaskDetails: false,
      userTaskData: [],
      processedBookingsForUser:[],
      plotWidth: 40.4, // Default width, will be calculated based on view
      lfree: 0,
      chkHours: 0,
      shiftHours: 0,
      freeHours: 0,
      weekdays: ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"],
      // Drag & Drop state
      isDragging: false,
      dragStartX: 0,
      dragStartDate: null,
      draggedBooking: null,
      dragOffset: 0,
      // Resize state
      isResizing: false,
      resizeStartX: 0,
      resizeStartDate: null,
      resizedBooking: null,
      resizeOffset: 0
    };
  },
  created: function () {
    var ths = this; 
  },
  mounted() {  
    this.$nextTick(() => {
    const firstDayEl = this.$el.querySelector('.resources--cal-unit');
    if (firstDayEl) {
      this.dayPixelWidth = firstDayEl.clientWidth;
    }
  });
    this.$set(this.user, 'showAllTasks', false);
    this.updatePlotWidth(this.currentView);
    this.preprocessBookings();
    this.setupDragAndDrop();
    this.setupResize();
    // this.$emit('reloadKey');

  },
  beforeDestroy() {
    this.cleanupDragAndDrop();
    this.cleanupResize();
  },
   watch: {
    user: { handler: "preprocessBookings", immediate: true, deep: true },
    allDays: { handler: "preprocessBookings", immediate: true },
    viewStart: { handler: "preprocessBookings", immediate: true },
    viewEnd: { handler: "preprocessBookings", immediate: true },
    currentView: {
      handler(newView) {
        this.updatePlotWidth(newView);
        this.preprocessBookings();
      },
      immediate: true
    },
  },
  computed: {    
  isReadonly() {
    return this.readonly;
  },
  parsedUserTaskData() {
    let data = this.user.userTaskData;
    if (typeof data === 'string') {
      try {
        data = JSON.parse(data);
      } catch (e) {
        data = [];
      }
    }
    return Array.isArray(data) ? data : [];
  },
  computedHeight() {
     // Calculate height based on maximum overlapping bookings per day
     const maxOverlapping = this.maxOverlappingBookings; // Computed property, no parentheses
     if (maxOverlapping > 0) {
       // Use same height calculation as calendar cells (76px base + 71.3px per overlapping task)
       const height = 76 + (maxOverlapping * 71.3) + (this.showTasks? 50:0);
       return `${height}px`;
     }
     return '97px';
  },
  maxOverlappingBookings() {
     // Calculate maximum number of overlapping bookings on any single day
     if (!this.user.bookings || this.user.bookings.length === 0) return 0;
     
     let maxOverlap = 0;
     const allDays = this.allDays;
     
     allDays.forEach(day => {
       const dayBookings = this.bookingsForDay(day);
       if (dayBookings.length > maxOverlap) {
         maxOverlap = dayBookings.length;
       }
     });
     
     return maxOverlap;
  },
  totalCalendarWidth() {
    // Calculate total width based on number of days and column width
    return (this.allDays.length * this.plotWidth) + 10;
  },
  calendarCellHeight() {
    const maxOverlapping = this.maxOverlappingBookings; 
    if (maxOverlapping > 0) {      
      return `${76 + (maxOverlapping * 71.3) + (this.showTasks?50:0) }px`;
    }
    return '97px';
  },
  allDays() {
      const days = [];
      if(this.currentView=='Month'){
        const start = new Date(this.fromdate.getFullYear(), this.fromdate.getMonth(), 1);
        const end = new Date(this.todate.getFullYear(), this.todate.getMonth() + 1, 0);
        while (start <= end) {
          days.push(new Date(start));
          start.setDate(start.getDate() + 1);
        } 
      }
      else{
        const start = new Date(this.fromdate);
        const end = new Date(this.todate);
        while (start <= end) {
          days.push(new Date(start));
          start.setDate(start.getDate() + 1);
        }    
      }       
      return days;
    }  
  },
  methods: {
    maybeStartResize(event, pb) {
    const rect = event.target.getBoundingClientRect();
    const offsetX = event.clientX - rect.left;
    const edgeThreshold = 8; 
    if (offsetX <= edgeThreshold) {
      this.startResize(pb, event, 'left');
    } else if (offsetX >= rect.width - edgeThreshold) {
      this.startResize(pb, event, 'right');
    } 
  },

  startResize(pb, event, direction) {
    event.preventDefault();
    this.resizingBooking = pb;
    this.resizeDirection = direction;
    this.startX = event.clientX;
    this.startWidth = pb.Width;
    this.startLeft = pb.leftPosition || 0;
    document.addEventListener('mousemove', this.onMouseMove);
    document.addEventListener('mouseup', this.onMouseUp);
  },

  onMouseMove(event) {
  if (!this.resizingBooking) return;
  const deltaX = event.clientX - this.startX;
  if (this.resizeDirection === 'right') {
    let newWidth = this.startWidth + deltaX;
    if (newWidth < 30) newWidth = 30;
    this.resizingBooking.Width = newWidth;
  } else if (this.resizeDirection === 'left') {
    let newLeft = this.startLeft + deltaX;
    let newWidth = this.startWidth - deltaX;
    if (newWidth < 30) {
      newWidth = 30;
      newLeft = this.startLeft + (this.startWidth - 30);
    }
    this.resizingBooking.leftPosition = newLeft;
    this.resizingBooking.Width = newWidth;
  }
},

onMouseUp(event) {
  if (this.resizingBooking) {
    this.$emit('bookingResized', this.resizingBooking);
  }
  this.resizingBooking = null;
  this.resizeDirection = null;
  document.removeEventListener('mousemove', this.onMouseMove);
  document.removeEventListener('mouseup', this.onMouseUp);
},
    getInitials(name) {
      if (!name) return '';
      const words = name.split(' ').filter(w => w.length > 0);
      if (words.length > 2) {
        // For names with more than 2 words, take first character of first 2 words
        return words.slice(0, 2)
          .map((n) => n[0])
          .join('')
          .toUpperCase();
      } else {
        // For names with 2 or fewer words, take first character of each word
        return words
          .map((n) => n[0])
          .join('')
          .toUpperCase();
      }
    },
    monthName(index) {
      const months = [
        "Jan", "Feb", "Mar", "Apr", "May", "Jun",
        "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
      ];
      return months[index];
    },
    isOffDay(date) {
      const offDays = this.user.companyOffday?.split(",") || [];
      return offDays.includes(String(date.getDay()));
    },
    isToday(date) {
      return new Date().toDateString() === date.toDateString();
    },  
    bookingsForDay(date) {
      return (this.user.bookings || []).filter(b => {
        const s = new Date(b.booking_start_date);
        const e = new Date(b.booking_end_date);
        return date >= s && date <= e;
      });
        const dayOfWeek = date.getDay();
        if (dayOfWeek === 0 || dayOfWeek === 6) return true; // Always off for Sunday and Saturday
        const offDaysStr = this.user.companyOffday?.split("^")[0] || "";
        const offDays = offDaysStr.split(",").map(d => parseInt(d)).filter(Boolean);
        return offDays.includes(dayOfWeek);
    },   
    BookingSaveClikc(data)
    {
        debugger
        data.Mtype='Edit';
        data.user=this.user;
        this.$emit('CellModelDetailData',data);
    },
    formatHours(minutes) {
      if (!minutes) return "0.00";
        const h = Math.floor(minutes / 60);
        const m = minutes % 60;
        return `${h}.${m}`;
    },    
    newtoggleOpen() {
      this.$emit("toggle-open", this.user.index);
    },
    newtoggleClose() {
      this.$emit("toggle-close", this.user.index);
    },
    RemoveUser(itemData) {
      this.isLoading = true;
      this.confirmR(
        this.$t("ConfirmRemove"),
        true,
        `${this.$t("Remove")} ${this.$t("User")}`,
        () => {
          if (itemData.userId != null) {
            if (this.user.userId === itemData.userId) {
                this.user = {}; 
                this.newtoggleClose();
                this.$emit('remove',itemData.index);
            }
          }
          this.isLoading = false;
        }
      );
    },
    AddTentativeLeave(itemData) {
      this.$emit('TentativeLeaveData',itemData);
    },
    OpenCloneSchedule(user) {
      this.$emit('CloneScheduleData',user);
    },
    
    async handleProjectTaskDetails(user) {
                this.isLoading = true;
                debugger
                this.showProjectTaskDetails = true;
                const startDate = this.formatDateForAPI(this.fromdate);
                const endDate = this.formatDateForAPI(this.todate);
                const isShow = 'ALL';
                // await this.GetUserProjectTaskData(user.userId, startDate, endDate, isShow);
                this.newtoggleOpen();
                this.$emit('ProjectTaskDetailData', { userId: user.userId, data: user});
        },

    dayClass(day) {
      const classes = [];
      if (this.isOffDay(day)) classes.push("unavailable week-end");     
      if (this.isCompanyHoliday(day)) classes.push("unavailable company-holiday");
      if (this.isTentativeLeave(day)) classes.push("tent-leave");
      if (this.isUserBusy(day)) classes.push("user-busy");     
      return classes.join(" ");
    },
    isCompanyHoliday(day) {
     // debugger
      const compHolidays = this.extractEpochArray(this.user.companyOffday, 1);
      return compHolidays.some(d => this.sameDate(d, day));
    },
    
  handleTentativeLeaveAdded(leaveInfo) {
      console.log("Tentative leave added (UI Only):", leaveInfo);
      // Initialize userTentativeLeave if it doesn't exist
      if (!this.user.userTentativeLeave) {
        this.$set(this.user, 'userTentativeLeave', []);
      }      
      let leaves = this.user.userTentativeLeave;      
      // Convert to array if it's a string
      if (typeof leaves === "string") {
        try {
          leaves = JSON.parse(leaves);
        } catch (e) {
          leaves = [];
        }
      }      
      // Ensure it's an array
      if (!Array.isArray(leaves)) {
        leaves = [];
      }      
      // Add the new leave with proper date objects
      const newLeave = {
        StartDate: new Date(leaveInfo.leaveData.StartDate),
        EndDate: new Date(leaveInfo.leaveData.EndDate),
        Type: leaveInfo.leaveData.Type,
        StatusId: 1001
      };      
      leaves.push(newLeave);      
      // Update with reactivity
      this.$set(this.user, 'userTentativeLeave', [...leaves]);      
      console.log("Updated UI tentative leaves:", this.user.userTentativeLeave);
    },
    isTentativeLeave(day) {
      let leaves = this.user.userTentativeLeave;
      if (!leaves) return false;      
      if (typeof leaves === "string") {
        try {
          leaves = JSON.parse(leaves);
        } catch (e) {
          return false;
        }
      }
      if (!Array.isArray(leaves)) return false;
      // Filter by StatusId 1001 (active tentative leaves)
      const activeLeaves = leaves.filter(l => l.StatusId === 1001);
      return activeLeaves.some(l => {
        const startDate = new Date(l.StartDate);
        const endDate = new Date(l.EndDate);
        startDate.setHours(0, 0, 0, 0);
        endDate.setHours(0, 0, 0, 0);
        const currentDay = new Date(day);
        currentDay.setHours(0, 0, 0, 0);          
        return currentDay >= startDate && currentDay <= endDate;
      });
    },
    getTentativeLeaveType(day) {
      let leaves = this.user.userTentativeLeave;
      if (!leaves) return null;
      if (typeof leaves === "string") {
        try {
          leaves = JSON.parse(leaves);
        } catch (e) {
          return null;
        }
      }
      if (!Array.isArray(leaves)) return null;
      const activeLeaves = leaves.filter(l => l.StatusId === 1001);
      const leave = activeLeaves.find(l => {
        const startDate = new Date(l.StartDate);
        const endDate = new Date(l.EndDate);
        startDate.setHours(0, 0, 0, 0);
        endDate.setHours(0, 0, 0, 0);
        const currentDay = new Date(day);
        currentDay.setHours(0, 0, 0, 0);
        return currentDay >= startDate && currentDay <= endDate;
      });
      return leave ? leave.Type : null;
    },
    getUserLeave(day) {
      // Check for approved/pending leaves
      const userLeaveDates = this.user.userLeave || "";
      if (!userLeaveDates) return null;
      
      const leaveArray = String(userLeaveDates).split(",");
      for (let i = 0; i < leaveArray.length; i++) {
        if (!leaveArray[i] || leaveArray[i] === "") continue;
        
        const parts = String(leaveArray[i]).split("^");
        const dateStr = parts[0];
        const leaveType = parts[1] || "";
        const leaveAmount = parts[2] || "0";
        
        if (!dateStr) continue;
        
        try {
          // Parse epoch date
          const epoch = parseInt(dateStr);
          if (isNaN(epoch)) continue;
          
          const leaveDate = new Date(epoch >= 13 ? epoch : epoch * 1000);
          leaveDate.setHours(0, 0, 0, 0);
          
          const currentDay = new Date(day);
          currentDay.setHours(0, 0, 0, 0);
          
          if (this.sameDate(leaveDate, currentDay)) {
            return {
              type: leaveType,
              amount: parseFloat(leaveAmount) || 0
            };
          }
        } catch (e) {
          continue;
        }
      }
      return null;
    },
    getUserAvailabilityTime(day) {
      // Get user availability time for the day (reduces available hours)
      const userAvailDates = this.user.userAvailbilityDates || "";
      if (!userAvailDates) return 0;
      
      const availArray = String(userAvailDates).split(",");
      for (let i = 0; i < availArray.length; i++) {
        if (!availArray[i] || availArray[i] === "") continue;
        
        const parts = String(availArray[i]).split("^");
        const startStr = parts[0];
        const endStr = parts[1] || "";
        
        if (!startStr) continue;
        
        try {
          const startEpoch = parseInt(startStr);
          if (isNaN(startEpoch)) continue;
          
          const startDate = new Date(startEpoch >= 13 ? startEpoch : startEpoch * 1000);
          startDate.setHours(0, 0, 0, 0);
          
          const currentDay = new Date(day);
          currentDay.setHours(0, 0, 0, 0);
          
          if (this.sameDate(startDate, currentDay) && endStr) {
            const endEpoch = parseInt(endStr);
            if (!isNaN(endEpoch)) {
              const endDate = new Date(endEpoch >= 13 ? endEpoch : endEpoch * 1000);
              const diffMs = endDate.getTime() - startDate.getTime();
              return Math.floor(diffMs / 60000); // Return minutes
            }
          }
        } catch (e) {
          continue;
        }
      }
      return 0;
    },
    isUserBusy(day) {     
      const availDates = this.parseAvailability(this.user.userAvailbilityDates);
      return availDates.some(d => this.sameDate(d, day));
    },  
    getUtilizationHeight(day) {
      // Dynamic height based on number of utilization blocks
      const blocks = this.getUtilizationBlocks(day);
      if (blocks.length > 1) {
        return `${45 + (blocks.length - 1) * 52}px`;
      }
      return '45px';
    },
    getUtilizationBlocks(day) {
      // Return array of utilization blocks with spans (matching old function logic)
      const blocks = [];
      
      // If off day or company holiday, return empty
      if (this.isOffDay(day) || this.isCompanyHoliday(day)) {
        return blocks;
      }
      
      const shiftHours = parseFloat(this.user.shiftHours || 8) * 60; // Convert to minutes
      const bookings = this.bookingsForDay(day);
      let freeHours = bookings.reduce((sum, pb) => sum + parseFloat(pb.raw.per_day_working_hours || 0), 0);
      
      // Get user leave information
      const userLeave = this.getUserLeave(day);
      let userLeaveAmount = 0;
      let getLeaveAmount = 0;
      
      if (userLeave && (userLeave.type === "LEAVE_APPROVED" || userLeave.type === "LEAVE_PENDING")) {
        if (Number(userLeave.amount) > 1) {
          getLeaveAmount = 1;
          userLeaveAmount = shiftHours;
        } else {
          getLeaveAmount = Number(userLeave.amount);
          userLeaveAmount = shiftHours / (1 / userLeave.amount);
        }
      }
      
      // Get tentative leave
      const tentativeLeaveType = this.getTentativeLeaveType(day);
      let tentativeLeaveAmount = 0;
      
      if (tentativeLeaveType) {
        if (tentativeLeaveType === "SL") {
          tentativeLeaveAmount = shiftHours * 0.25;
        } else if (tentativeLeaveType === "HL") {
          tentativeLeaveAmount = shiftHours * 0.5;
        } else if (tentativeLeaveType === "FL") {
          tentativeLeaveAmount = shiftHours;
        }
        userLeaveAmount += tentativeLeaveAmount;
        if (userLeaveAmount > shiftHours) {
          userLeaveAmount = shiftHours;
        }
      }
      
      // Get user availability time (reduces available hours)
      const totalTimeUserFree = this.getUserAvailabilityTime(day);
      
      // Calculate final hours (matching old function logic)
      const lfree = Number((shiftHours - freeHours).toFixed(2));
      let chkHours = Math.min(Number(freeHours) + Number(userLeaveAmount), shiftHours);
      
      const availableHours = shiftHours - chkHours;
      
      // Build utilization blocks
      if (lfree < 0) {
        // Overload case - show 0.00 in grey and overload in red
        blocks.push({
          spans: [
            { class: "boxgrey", text: "0.00" },
            { class: "boxred", text: this.formatHours(Math.abs(freeHours)) }
          ]
        });
        
        if (totalTimeUserFree > 0) {
          blocks.push({
            spans: [
              { class: "boxpurple", text: this.formatHours(totalTimeUserFree) }
            ]
          });
        }
      } else {
        // Normal case
        const availableHoursFormatted = this.formatHours(Math.abs(availableHours));
        const bookedHoursFormatted = this.formatHours(Math.abs(freeHours));
        
        if (availableHoursFormatted === this.formatHours(shiftHours)) {
          // Only show available hours if they equal shift hours
          blocks.push({
            spans: [
              { class: "boxgreen", text: availableHoursFormatted }
            ]
          });
        } else {
          // Show both available and booked hours
          blocks.push({
            spans: [
              { class: "boxgreen", text: availableHoursFormatted },
              { class: "boxpurple", text: bookedHoursFormatted }
            ]
          });
          
          if (totalTimeUserFree > 0) {
            blocks.push({
              spans: [
                { class: "boxgreen", text: availableHoursFormatted },
                { class: "boxpurple", text: this.formatHours(totalTimeUserFree) }
              ]
            });
          }
        }
      }
      
      return blocks;
    },
    getUtilizationHours(day) {
      // Legacy method - returns first available hours text
      const blocks = this.getUtilizationBlocks(day);
      if (blocks.length > 0 && blocks[0].spans.length > 0) {
        return blocks[0].spans[0].text;
      }
      return '';
    },
    utilizationColor(day) {
      // Legacy method - returns first color class
      const blocks = this.getUtilizationBlocks(day);
      if (blocks.length > 0 && blocks[0].spans.length > 0) {
        return blocks[0].spans[0].class;
      }
      if (this.isOffDay(day)) return "";
      if (this.isCompanyHoliday(day)) return "";
      if (this.isUserBusy(day)) return "boxpurple";
      return "boxgreen";
    },
    leaveType(day) {
        // Check for user leave (approved/pending) first
        const userLeave = this.getUserLeave(day);
        if (userLeave && (userLeave.type === "LEAVE_APPROVED" || userLeave.type === "LEAVE_PENDING")) {
          return { 
            icon: userLeave.type === "LEAVE_PENDING" ? "fa fa-ship text-primary" : "fa fa-ship text-success", 
            title: userLeave.type === "LEAVE_PENDING" ? "Leave Pending" : "Leave Approved",
            type: userLeave.type,
            amount: userLeave.amount
          };
        }
        
        // Check for tentative leave
        if (this.isTentativeLeave(day)) {
          return { icon: "fa fa-user-times text-muted", title: "Tentative Leave" };
        }
        
        if (this.isCompanyHoliday(day)) {
          return { icon: "text-danger", title: "Company Holiday" };
        }
        
        if (this.isUserBusy(day)) {
          return { icon: "fa fa-clock text-warning", title: "User Busy" };
        }
        
        return null;
    },
    sameDate(a, b) {
        return (
          a.getDate() === b.getDate() &&
          a.getMonth() === b.getMonth() &&
          a.getFullYear() === b.getFullYear()
        );
      },
      comparesameDate(day, startDate, endDate) {
      // Normalize all dates to midnight to prevent time zone or time-of-day mismatches
        const normalize = (date) => {
          const d = new Date(date);
          d.setHours(0, 0, 0, 0);
          return d;
      };

      const current = normalize(day);
      const start = normalize(startDate);
      const end = normalize(endDate);

      // Return true if day is within the booking range (inclusive)
      return current >= start && current <= end;
  },
      extractEpochArray(data, index) {
       // debugger
        // Extracts date part from ^-separated offday string
        if (!data) return [];
        const parts = String(data).split("^")[index] || "";
        const dates = parts.split(",").filter(Boolean);
        return dates.map(d => new Date(parseInt(d)));
      },
      parseAvailability(data) {
        if (!data) return [];
        const arr = String(data).split(",");
        return arr
          .map((d) => d.split("^")[0])
          .filter(Boolean)
          .map((x) => new Date(parseInt(x)));
      },  
      formatDateForAPI(date) {
          if (!date) return '';
          const d = new Date(date);
          const year = d.getFullYear();
          const month = String(d.getMonth() + 1).padStart(2, '0');
          const day = String(d.getDate()).padStart(2, '0');
          return `${year}-${month}-${day}`;
      },
    
    onCellDblClick(day,dayIndex){
        const cellInfo = {
        userId: this.user.userId,
        userName: this.user.userName,
        date: day.getTime(), 
        dateObj: day,
        user: this.user,
        shiftHours: this.shifthours,
        dayIndex: dayIndex,
        Mtype:'Create',
        user:this.user
      };
      this.$emit('CellModelDetailData',cellInfo);
    }, 
    AllUserTaskData(data){
      var ths=this;
      var StartDate=ths.fromdate.getTime()/1000;
      var EndDate=ths.todate.getTime()/1000;
      var userId=data.userId;
      ths.$set(data, 'showAllTasks', true);
      ths.$emit('AllUserTaskData',userId,StartDate,EndDate);
    },
    HideUserTaskData(data){
      var ths=this;
      ths.$set(data, 'showAllTasks', false);
      ths.showTasks=false;
    },
    normalize(date) {
      const d = new Date(date);
      d.setHours(0, 0, 0, 0);
      return d;
    },
    isSameDay(a, b) {
      if (!a || !b) return false;
      const A = this.normalize(a).getTime();
      const B = this.normalize(b).getTime();
      return A === B;
    },
    dayInRange(day, start, end) {
      const d = this.normalize(day).getTime();
      const s = this.normalize(start).getTime();
      const e = this.normalize(end).getTime();
      return d >= s && d <= e;
    },
    // if booking date is an ISO string or epoch or custom .EpochToDateTime-like, convert to Date
    parseBookingDate(val) {
      if (!val && val !== 0) return null;
      // If it's already a Date
      if (val instanceof Date) return new Date(val);
      // If numeric epoch (ms)
      if (!isNaN(val) && String(val).length >= 10) {
        // treat as milliseconds if >= 13 digits, else seconds
        const s = String(val).length;
        if (s >= 13) return new Date(Number(val));
        return new Date(Number(val) * 1000);
      }
      // If string ISO
      if (typeof val === "string") {
        // If string contains 'T' assume ISO
        if (val.includes("T")) return new Date(val);
        // if string numeric
        if (!isNaN(val)) {
          const s = val.length;
          if (s >= 13) return new Date(Number(val));
          return new Date(Number(val) * 1000);
        }
        // fallback
        const got = new Date(val);
        if (!isNaN(got.getTime())) return got;
      }
      // fallback
      return new Date(val);
    },
    daysBetween(a, b) {
      const A = this.normalize(a);
      const B = this.normalize(b);
      return Math.max(0, Math.round((B - A) / (24 * 3600 * 1000)) + 1); // inclusive count
    },
     showhoursPerDay: function (value) {
           var hours = Math.floor(value / 60);
            value %= 60;
           var  minutes = Math.floor(value % 60);
            if (minutes < 10)
                minutes = '0' + minutes;
            return hours + 'H : ' + minutes + 'M';

        },   
    preprocessBookings() {   
      this.processedBookingsForUser = [];
      if (!this.user || !Array.isArray(this.user.bookings)) return;
      const visibleStart = this.normalize(this.fromdate);
      const visibleEnd = this.normalize(this.todate);
      for (let i = 0; i < this.user.bookings.length; i++) {
        const raw = this.user.bookings[i];
        if (raw.is_change !== undefined && Number(raw.is_change) === 3) continue;
        let bookingStart = this.parseBookingDate(raw.booking_start_date);
        let bookingEnd = this.parseBookingDate(raw.booking_end_date);
        if (!bookingStart || isNaN(bookingStart.getTime())) bookingStart = new Date(0);
        if (!bookingEnd || isNaN(bookingEnd.getTime())) bookingEnd = new Date(0);
        bookingStart = this.normalize(bookingStart);
        bookingEnd = this.normalize(bookingEnd);
        // if (bookingEnd < visibleStart || bookingStart > visibleEnd) {
        //   continue;
        // }
        const displayStart = bookingStart;
        // < visibleStart ? visibleStart : bookingStart;
        const displayEnd = bookingEnd 
        // > visibleEnd ? visibleEnd : bookingEnd;
        const localDays = this.daysBetween(displayStart, displayEnd); 
        const width = localDays * this.plotWidth;
        const totalDays = this.daysBetween(bookingStart, bookingEnd);
        const tooltip = raw.task_name
          ? `${raw.project_name} | ${raw.task_name} | ${this.showhoursPerDay(raw.per_day_working_hours || "")} Daily | Total ${totalDays} Days`
          : `${raw.project_name} | ${this.showhoursPerDay(raw.per_day_working_hours || "")} Daily | Total ${totalDays} Days`;
        const pb = {
          raw: raw,
          booking_id: raw.booking_id,
          booking_start_date: new Date(raw.booking_start_date),
          booking_end_date: new Date(raw.booking_end_date),
          start: bookingStart,
          end: bookingEnd,
          displayStart: displayStart,
          displayEnd: displayEnd,
          localDays: localDays,
          Width: width,
          project_name: raw.project_name,
          task_name: raw.task_name,
          per_day_working_hours: this.showhoursPerDay(raw.per_day_working_hours),
          total: totalDays,
          Tooltip: tooltip,
          ColorClass: raw.resClass || raw.colorClass || "RS_draggable_box1 ui-resizable", 
        };
        this.processedBookingsForUser.push(pb);
      }
    },
    bookingsForDay(day) {
      const matched = [];
      const d = this.normalize(day).getTime();
      for (const pb of this.processedBookingsForUser) {
        const s = this.normalize(pb.displayStart).getTime();
        const e = this.normalize(pb.displayEnd).getTime();
        if (d >= s && d <= e) matched.push(pb);
      }
      return matched;
    },
    isBookingStart(day, pb) {
      return this.isSameDay(day, pb.displayStart);
    },
    isBetweenBooking(day, pb) {
      const current = this.normalize(day).getTime();
      const start = this.normalize(pb.displayStart).getTime();
      const end = this.normalize(pb.displayEnd).getTime();
      return current > start && current <= end;
    },
    // DRAG & DROP METHODS
    onBookingMouseDown(event, pb) {
      if (this.readonly || event.target.classList.contains('resize-handle')) {
        return;
      }
      // Prevent drag if clicking on resize handle
      if (event.button !== 0) return; // Only left mouse button
      
      this.isDragging = true;
      this.dragStartX = event.clientX;
      this.draggedBooking = pb;
      this.dragStartDate = new Date(pb.raw.booking_start_date);
      
      // Prevent text selection during drag
      event.preventDefault();
      document.body.style.userSelect = 'none';
      document.body.style.cursor = 'grabbing';
      document.body.classList.add('dragging-booking');
      
      // Add global event listeners
      document.addEventListener('mousemove', this.onDragMove);
      document.addEventListener('mouseup', this.onDragEnd);
    },
    onDragMove(event) {
      if (!this.isDragging || !this.draggedBooking) return;
      
      const deltaX = event.clientX - this.dragStartX;
      const daysOffset = Math.round(deltaX / this.plotWidth);
      
      if (daysOffset !== this.dragOffset) {
        this.dragOffset = daysOffset;
        // Visual feedback - booking will show at new position
        this.$forceUpdate();
      }
    },
    onDragEnd(event) {
      if (!this.isDragging || !this.draggedBooking) return;
      
      // Calculate new dates
      const deltaX = event.clientX - this.dragStartX;
      const daysOffset = Math.round(deltaX / this.plotWidth);
      
      if (daysOffset !== 0 && this.draggedBooking) {
        const booking = this.draggedBooking.raw;
        const originalStart = new Date(booking.booking_start_date);
        const originalEnd = new Date(booking.booking_end_date);
        const duration = this.daysBetween(originalStart, originalEnd);
        
        // Calculate new start date
        const newStart = new Date(originalStart);
        newStart.setDate(newStart.getDate() + daysOffset);
        
        // Calculate new end date (maintain duration)
        const newEnd = new Date(newStart);
        newEnd.setDate(newEnd.getDate() + duration);
        
        // Update booking locally
        this.updateBookingDates(booking, newStart, newEnd);
      }
      
      // Cleanup
      this.isDragging = false;
      this.draggedBooking = null;
      this.dragOffset = 0;
      this.dragStartX = 0;
      this.dragStartDate = null;
      
      document.body.style.userSelect = '';
      document.body.style.cursor = '';
      document.body.classList.remove('dragging-booking');
      document.removeEventListener('mousemove', this.onDragMove);
      document.removeEventListener('mouseup', this.onDragEnd);
      
      this.$forceUpdate();
    },
    // RESIZE METHODS
    onResizeMouseDown(event, pb) {
      if (this.readonly) return;
      
      if (event.button !== 0) return;
      
      this.isResizing = true;
      this.resizeStartX = event.clientX;
      this.resizedBooking = pb;
      this.resizeStartDate = new Date(pb.raw.booking_end_date);
      
      event.preventDefault();
      event.stopPropagation();
      document.body.style.userSelect = 'none';
      document.body.style.cursor = 'ew-resize';
      document.body.classList.add('resizing-booking');
      
      document.addEventListener('mousemove', this.onResizeMove);
      document.addEventListener('mouseup', this.onResizeEnd);
    },
    onResizeMove(event) {
      if (!this.isResizing || !this.resizedBooking) return;
      
      const deltaX = event.clientX - this.resizeStartX;
      const daysOffset = Math.round(deltaX / this.plotWidth);
      
      if (daysOffset !== this.resizeOffset) {
        this.resizeOffset = daysOffset;
        this.$forceUpdate();
      }
    },
    onResizeEnd(event) {
      if (!this.isResizing || !this.resizedBooking) return;
      
      const deltaX = event.clientX - this.resizeStartX;
      const daysOffset = Math.round(deltaX / this.plotWidth);
      
      if (daysOffset !== 0 && this.resizedBooking) {
        const booking = this.resizedBooking.raw;
        const originalEnd = new Date(booking.booking_end_date);
        
        // Calculate new end date
        const newEnd = new Date(originalEnd);
        newEnd.setDate(newEnd.getDate() + daysOffset);
        
        // Ensure end date is not before start date
        const startDate = new Date(booking.booking_start_date);
        if (newEnd < startDate) {
          newEnd.setTime(startDate.getTime());
        }
        
        // Update booking locally
        this.updateBookingDates(booking, new Date(booking.booking_start_date), newEnd);
      }
      
      // Cleanup
      this.isResizing = false;
      this.resizedBooking = null;
      this.resizeOffset = 0;
      this.resizeStartX = 0;
      this.resizeStartDate = null;
      
      document.body.style.userSelect = '';
      document.body.style.cursor = '';
      document.body.classList.remove('resizing-booking');
      document.removeEventListener('mousemove', this.onResizeMove);
      document.removeEventListener('mouseup', this.onResizeEnd);
      
      this.$forceUpdate();
    },
    updateBookingDates(data, newStartDate, newEndDate) {
      const bookingIndex = this.user.bookings.findIndex(b => b.booking_id === data.booking_id);
      data.booking_end_date=newEndDate;
      if(data.total == '' || data.total == undefined || data ==null)
      {
        data.total=0;
      }
      if (bookingIndex !== -1) {
        const formattedBooking = {
          booking_id: data.booking_id,
          resource_id: data.resource_id,
          project_id: data.project_id || null,
          task_Id: data.task_Id || null,
          description: data.description || "",
          start_date: this.formatDateForAPI(data.booking_start_date),
          end_date: this.formatDateForAPI(data.booking_end_date),
          specific_day_start_time: data.specific_start_time ? data.specific_start_time : null,
          specific_day_stop_time: data.specific_stop_time ? data.specific_stop_time: null,
          per_day_working_hours: data.per_day_working_hours || 0,
          working_on_off_days: data.working_on_off_days || false,
          total: data.total || 0,
          is_change: data.is_change || false,
          task_type: data.task_type || false
       }
        const resourceData = {
            bookings: formattedBooking,
            tentativeLeave: []
         };
         this.saveToAPI(resourceData);
      }
    },
    async saveToAPI(resourceData) {
         try {
          //debugger
          this.isLoading=true;
            console.log("Sending to API:", resourceData);
            const params = {
               tblResources: resourceData.bookings,
               LEAVE_JSON:resourceData.tentativeLeave
            };
            const response = await DataService.SaveResourceScheduling(params);
            if (response.data.msg === "SUCCESS") {
              //debugger
              this.isLoading=false;
            this.ShowAlert(this.$t("AddedSuccess",[this.$t("ResourceScheduling")]),"success",true,this.$t("Alert"));         
            this.$emit('save-completed', true);
            } 
            else if(response.data.msg === "EXIST")
            {
              this.isLoading=false;
              this.ShowAlert(this.$t("AlreadyExists",[this.$t("ResourceScheduling")]),"failure",true,this.$t("Alert"));         
              // Still notify parent that save cycle completed so it can refresh if needed
              this.$emit('save-completed', true);
            }
            else {
                   this.isLoading=false;
                  this.ShowAlert(this.$t("AddedError",[this.$t("ResourceScheduling")]),"failure",true,this.$t("Alert"));
                  this.$emit('save-completed', false);
            }
         } 
         catch (error) {
            console.error("Error saving resource scheduling:", error);
            this.showErrorMessage("Error saving resource scheduling.");
            this.$emit('save-completed', false);
         }
      },
    updatePlotWidth(view) {
      // Set column width - must match SchedulerHeader columnWidth
      // This ensures tasks align with date columns
      switch(view) {
        case 'Day':
          this.plotWidth = 170; // Wider columns for day view
          break;
        case 'Month':
        case 'week':
        default:
          this.plotWidth = 40; // Standard width for week and month views
          break;
      }
    },
    setupDragAndDrop() {
      // Additional setup if needed
    },
    cleanupDragAndDrop() {
      // Cleanup if needed
      document.removeEventListener('mousemove', this.onDragMove);
      document.removeEventListener('mouseup', this.onDragEnd);
    },
    setupResize() {
      // Additional setup if needed
    },
    cleanupResize() {
      // Cleanup if needed
      document.removeEventListener('mousemove', this.onResizeMove);
      document.removeEventListener('mouseup', this.onResizeEnd);
    },
    // calculateUtilisation(data) {  
    //   debugger    
    //     var freeHours = 0;
    //     var shiftHours = 480; 
    //     var userLeave = false;
    //     var userLeaveAmount = 0;
    //     var userTentativeLeaveAmount = null;
    //     var userLeaveType = "";   
    //     let getLeaveAmount = 0;
    //     this.lfree = (shiftHours - freeHours).toFixed(2);

    //   // Handle approved/pending leave
    //   if (userLeave && (userLeaveType === "LEAVE_APPROVED" || userLeaveType === "LEAVE_PENDING")) {
    //     if (Number(userLeaveAmount) > 1) {
    //       userLeaveAmount = 1;
    //       getLeaveAmount = Number(userLeaveAmount);
    //     } else {
    //       getLeaveAmount = Number(userLeaveAmount);
    //       userLeaveAmount = shiftHours / (1 / userLeaveAmount);
    //     }
    //   }

    //   // Handle tentative leave
    //   if (userTentativeLeaveAmount) {
    //     let tempAmt = 0;
    //     if (userTentativeLeaveAmount === "SL") tempAmt = shiftHours * 0.25;
    //     else if (userTentativeLeaveAmount === "HL") tempAmt = shiftHours * 0.5;
    //     else if (userTentativeLeaveAmount === "FL") tempAmt = shiftHours;
    //     userLeaveAmount += tempAmt;
    //     if (userLeaveAmount > shiftHours) userLeaveAmount = shiftHours;
    //   }

    //   this.chkHours = Math.min(Number(freeHours) + Number(userLeaveAmount), shiftHours);
